export interface OracleSource {
  title: string;
  uri: string;
}

export interface ComparisonOption {
  title: string;
  description: string;
  score: number;
}

export interface Perspective {
  verdict: string;
  analysis: string;
}

export interface OracleResponse {
  type: 'SINGLE' | 'COMPARISON';
  title: string; 
  verdict: string; 
  category: 'PRODUCT' | 'MEDIA' | 'LIFE' | 'TECH' | 'RELATIONAL' | 'KNOWLEDGE' | 'FUTURE' | 'BOOKS' | 'MUSIC' | 'ARCHITECTURE' | 'GAMING' | 'SCIENCE' | 'GASTRONOMY';
  genre?: string;
  reasoning: string;
  sources?: OracleSource[];
  base64Image?: string; 
  imageUrl?: string;
  imageStyleLabel?: string;
  language?: 'EN' | 'RU';
  isFallback?: boolean;
  isDaily?: boolean;
  perspectives?: {
    psychoanalysis?: Perspective;
    gestalt?: Perspective;
    russian_philosophy?: Perspective;
    german_philosophy?: Perspective;
    existential?: Perspective;
    theological?: Perspective;
    buddhist?: Perspective;
    post_modern?: Perspective;
  };
  detailedAnalysis?: string; 
  comparison?: {
    optionA: ComparisonOption;
    optionB: ComparisonOption;
    winner: 'A' | 'B';
  };
}

export interface HistoryItem {
  id: string;
  query: string;
  response: OracleResponse;
  timestamp: number;
  logicScore: number;
  chaosScore: number;
}

export interface OracleState {
  status: 'IDLE' | 'THINKING' | 'REVEALED' | 'ERROR';
  query: string;
  response: OracleResponse | null;
  logicScore: number; 
  chaosScore: number; 
  error?: string;
  attempts: number; 
}

import React, { useState, useRef, useEffect } from 'react';
import html2canvas from 'html2canvas';
import { OracleState, OracleResponse, HistoryItem } from './types';
import { consultOracle, regenerateOracleImage, translateOracleResponse, speakText } from './services/oracleService';
import { RatioIndicator } from './components/RatioIndicator';
import { LoadingScreen } from './components/LoadingScreen';
import { ThemeBackground } from './components/ThemeBackground';

type Theme = 'SUPREMATIST' | 'IMPRESSIONIST';
type Language = 'EN' | 'RU';
type FrameworkType = 'DEFAULT' | 'PSYCHOANALYSIS' | 'GESTALT' | 'RUSSIAN' | 'GERMAN' | 'EXISTENTIAL' | 'THEOLOGICAL' | 'BUDDHIST' | 'POST_MODERN';

const TRANSLATIONS = {
  EN: {
    ask: "ASK", daily: "DAILY REVELATION", placeholder: "What do you seek?", logic: "Logic", chaos: "Chaos", voidEmpty: "The void is silent", return: "Return", winner: "THE WINNER", verdict: "THE VERDICT", readPerspectives: "ALL PERSPECTIVES", closeVerdict: "CLOSE", saveArtifact: "SAVE ARTEFACT", saveCard: "Save Card", saveImage: "Save Picture", newQuery: "NEW QUERY", sources: "Evidence Found", studyFurther: "Study Further", imageLost: "Vision lost.", title: "The Oracle\nof Chance", footer: "Anti-Algorithm v1.5", errorMsg: "A paradox has occurred.", history: "HISTORY", optionA: "Option A", optionB: "Option B", translating: "Translating...",
    manualCalibration: "Manual Calibration",
    backupWarning: "backup generator used - pollinations",
    dailyContemplation: "Daily Contemplation",
    frameworks: { DEFAULT: "Ontological Core", PSYCHOANALYSIS: "Psychoanalysis", GESTALT: "Gestalt", RUSSIAN: "Russian Philosophy", GERMAN: "German Philosophy", EXISTENTIAL: "Existentialism", THEOLOGICAL: "Theology", BUDDHIST: "Zen Buddhism", POST_MODERN: "Post-Modernism" }
  },
  RU: {
    ask: "СПРОСИТЬ", daily: "ЕЖЕДНЕВНОЕ ОТКРОВЕНИЕ", placeholder: "Что вы ищете?", logic: "Логика", chaos: "Хаос", voidEmpty: "Пустота безмолвна", return: "Назад", winner: "ПОБЕДИТЕЛЬ", verdict: "ВЕРДИКТ", readPerspectives: "ВСЕ ПЕРСПЕКТИВЫ", closeVerdict: "ЗАКРЫТЬ", saveArtifact: "АРТЕФАКТ", saveCard: "Сохранить Карту", saveImage: "Сохранить Фото", newQuery: "НОВЫЙ ЗАПРОС", sources: "Улики", studyFurther: "Изучить подробнее", imageLost: "Видение потеряно.", title: "Оракул\nСлучая", footer: "Анти-Алгоритм v1.5", errorMsg: "Произошел парадокс.", history: "ИСТОРИЯ", optionA: "Вариант А", optionB: "Вариант Б", translating: "Перевод...",
    manualCalibration: "Ручная калибровка",
    backupWarning: "используется резервный генератор - pollinations",
    dailyContemplation: "Ежедневное размышление",
    frameworks: { DEFAULT: "Ядро", PSYCHOANALYSIS: "Психоанализ", GESTALT: "Гештальт", RUSSIAN: "Русская философия", GERMAN: "Немецкая философия", EXISTENTIAL: "Экзистенциализм", THEOLOGICAL: "Теология", BUDDHIST: "Дзен", POST_MODERN: "Постмодернизм" }
  }
};

const Icons = {
  ArrowLeft: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>,
  History: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>,
  Speaker: ({ muted, loading }: { muted: boolean, loading: boolean }) => (
    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24" className={loading ? 'animate-pulse' : ''}>
      {muted ? <><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></> : <><path d="M11 5l-5 4H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></>}
    </svg>
  ),
  Close: () => <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12"/></svg>,
  Settings: () => <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1"/></svg>,
  Download: () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>,
  Sparkle: () => <svg width="14" height="14" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>,
};

export const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('SUPREMATIST');
  const [uiLanguage, setUiLanguage] = useState<Language>('EN');
  const [initialChaos] = useState(() => Math.floor(Math.random() * 80) + 10);
  const [state, setState] = useState<OracleState>({ status: 'IDLE', query: '', response: null, logicScore: 100 - initialChaos, chaosScore: initialChaos, attempts: 0 });
  const [activeFramework, setActiveFramework] = useState<FrameworkType>('DEFAULT');
  const [isMuted, setIsMuted] = useState(true);
  const [isTtsLoading, setIsTtsLoading] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);
  const [showPerspectivesModal, setShowPerspectivesModal] = useState(false);
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isManual, setIsManual] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const captureRef = useRef<HTMLDivElement>(null);

  const isRenoir = theme === 'IMPRESSIONIST';
  const t = TRANSLATIONS[uiLanguage];

  useEffect(() => {
    const rotate = () => {
      const core = [
        "Does the algorithm have a soul?", "Memory vs Resistance", "Ethics of eternal recurrence",
        "Minimalism vs Baroque", "City vs Wilderness", "Manual vs Automatic",
        "Should I quit my job?", "Trust the chaos?", "What is time?", "History of Silk Road"
      ];
      setSuggestions(core.sort(() => 0.5 - Math.random()).slice(0, 5));
    };
    rotate();
    const interval = setInterval(rotate, 120000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('oracle_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) { console.error("History reset"); }
    }
  }, []);

  useEffect(() => {
    if (history.length > 0) {
      const pruned = history.map((item, index) => {
        if (index < 1) return item;
        const { base64Image, ...restResponse } = item.response;
        return { ...item, response: restResponse as OracleResponse };
      });
      try {
        localStorage.setItem('oracle_history', JSON.stringify(pruned));
      } catch (e) {
        const strictlyPruned = history.map(item => {
          const { base64Image, ...restResponse } = item.response;
          return { ...item, response: restResponse as OracleResponse };
        });
        localStorage.setItem('oracle_history', JSON.stringify(strictlyPruned));
      }
    }
  }, [history]);

  useEffect(() => {
    if (state.status === 'REVEALED' && state.response) handleImageRegen();
  }, [theme]);

  // Translate content when language changes
  useEffect(() => {
    if (state.status === 'REVEALED' && state.response && state.response.language !== uiLanguage) {
      handleContentTranslation();
    }
  }, [uiLanguage]);

  const stopAudio = () => {
    if (audioSourceRef.current) { try { audioSourceRef.current.stop(); } catch(e) {} audioSourceRef.current = null; }
    if (audioContextRef.current) { audioContextRef.current.close(); audioContextRef.current = null; }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (/[а-яА-ЯЁё]/.test(val) && uiLanguage !== 'RU') setUiLanguage('RU');
    else if (/[a-zA-Z]/.test(val) && uiLanguage !== 'EN') setUiLanguage('EN');
  };

  const handleContentTranslation = async () => {
    if (!state.response) return;
    setIsTranslating(true);
    try {
      const translated = await translateOracleResponse(state.response, uiLanguage);
      setState(prev => ({ ...prev, response: translated }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsTranslating(false);
    }
  };

  const handleImageRegen = async () => {
    if (!state.response) return;
    setIsImageLoading(true);
    try {
      const result = await regenerateOracleImage(state.response, theme, state.chaosScore);
      setState(prev => ({
        ...prev,
        response: prev.response ? { ...prev.response, base64Image: result.image, imageStyleLabel: result.label, imageUrl: result.url, isFallback: result.isFallback || prev.response.isFallback } : null
      }));
    } catch (e) { console.error(e); } finally { setIsImageLoading(false); }
  };

  const runQuery = async (queryText: string, isDaily = false) => {
    if (!queryText) return;
    setState(s => ({ ...s, status: 'THINKING', query: queryText }));
    try {
      const response = await consultOracle(queryText, state.chaosScore, theme, uiLanguage);
      const taggedResponse = { ...response, isDaily };
      setState(s => ({ ...s, status: 'REVEALED', response: taggedResponse }));
      setHistory(prev => [{ id: Date.now().toString(), query: queryText, response: taggedResponse, timestamp: Date.now(), logicScore: state.logicScore, chaosScore: state.chaosScore }, ...prev].slice(0, 15));
      setActiveFramework('DEFAULT');
    } catch (e) { 
      setState(s => ({ ...s, status: 'ERROR', error: e instanceof Error ? e.message : 'Paradox in the void.' })); 
    }
  };

  const handleDailyOracle = async () => {
    const today = new Date().toISOString().split('T')[0];
    const cacheKey = `oracle_daily_${uiLanguage}`;
    const cached = localStorage.getItem(cacheKey);

    if (cached) {
      try {
        const parsed = JSON.parse(cached);
        if (parsed.date === today) {
          stopAudio();
          setState(s => ({ ...s, status: 'REVEALED', response: parsed.response, query: parsed.query, chaosScore: 50, logicScore: 50 }));
          return;
        }
      } catch (e) { console.error("Daily cache corrupt"); }
    }

    // No cache or old cache
    const dailyPrompt = uiLanguage === 'EN' 
      ? `Give me a unique philosophical contemplation for today, ${new Date().toDateString()}. Focus on the theme of time, chance, and the intersection of order and chaos.`
      : `Дай мне уникальное философское размышление на сегодня, ${new Date().toLocaleDateString('ru-RU')}. Сосредоточься на теме времени, случая и пересечения порядка и хаоса.`;

    setState(s => ({ ...s, status: 'THINKING', query: dailyPrompt, chaosScore: 50, logicScore: 50 }));
    try {
      const response = await consultOracle(dailyPrompt, 50, theme, uiLanguage);
      const taggedResponse = { ...response, isDaily: true };

      const dailyData = { date: today, query: dailyPrompt, response: taggedResponse };
      localStorage.setItem(cacheKey, JSON.stringify(dailyData));

      setState(s => ({ ...s, status: 'REVEALED', response: taggedResponse }));
      setHistory(prev => [{ id: Date.now().toString(), query: dailyPrompt, response: taggedResponse, timestamp: Date.now(), logicScore: 50, chaosScore: 50 }, ...prev].slice(0, 15));
    } catch (e) {
      setState(s => ({ ...s, status: 'ERROR', error: e instanceof Error ? e.message : 'Void paradox during daily revelation.' }));
    }
  };

  const saveArtifactAsImage = async () => {
    if (!captureRef.current) return;
    try {
      await new Promise(r => setTimeout(r, 100));
      const canvas = await html2canvas(captureRef.current, { backgroundColor: isRenoir ? '#0f0505' : '#ffffff', useCORS: true, scale: 2 });
      const link = document.createElement('a');
      link.download = `oracle-artifact-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (e) { console.error("Capture failed:", e); }
  };

  const activeAnalysis = (() => {
    const r = state.response;
    if (!r) return "";
    if (activeFramework === 'DEFAULT') return r.detailedAnalysis || r.verdict;
    const keyMap: any = { 
      'PSYCHOANALYSIS': 'psychoanalysis', 'GESTALT': 'gestalt', 
      'RUSSIAN': 'russian_philosophy', 'GERMAN': 'german_philosophy', 
      'EXISTENTIAL': 'existential', 'THEOLOGICAL': 'theological', 
      'BUDDHIST': 'buddhist', 'POST_MODERN': 'post_modern' 
    };
    const framework = (r.perspectives as any)?.[keyMap[activeFramework]];
    return framework?.analysis || framework?.verdict || r.detailedAnalysis || r.verdict;
  })();

  const NavButton = ({ onClick, children, className = "" }: any) => (
    <button onClick={onClick} className={`w-11 h-11 rounded-full border flex items-center justify-center backdrop-blur-xl transition-all shadow-xl active:scale-95 ${isRenoir ? 'bg-amber-950/40 border-amber-900/20 text-amber-100' : 'bg-white/40 border-black/5 text-black'} ${className}`}>{children}</button>
  );

  const handleSpeakerToggle = async () => {
    const targetMute = !isMuted; setIsMuted(targetMute);
    if (targetMute) stopAudio();
    else if (state.response) {
      setIsTtsLoading(true);
      try {
        const { context, source } = await speakText(activeAnalysis, uiLanguage);
        audioContextRef.current = context; audioSourceRef.current = source;
        source.onended = () => { setIsMuted(true); setIsTtsLoading(false); };
      } catch (e) { setIsMuted(true); } finally { setIsTtsLoading(false); }
    }
  };

  const GlobalUI = (
    <>
      {state.response?.isFallback && (
        <div className={`fixed top-0 left-0 w-full z-[600] py-1 text-center text-[8px] font-black uppercase tracking-widest ${isRenoir ? 'bg-amber-900 text-white' : 'bg-red-600 text-white'}`}>
          {t.backupWarning}
        </div>
      )}
      <div className="fixed top-4 left-4 z-[500] flex gap-3">
        {state.status !== 'IDLE' && <NavButton onClick={() => { stopAudio(); setState(s => ({ ...s, status: 'IDLE' })); }}><Icons.ArrowLeft /></NavButton>}
        <NavButton onClick={handleSpeakerToggle} className={!isMuted ? 'ring-2 ring-red-500' : 'opacity-40'}><Icons.Speaker muted={isMuted} loading={isTtsLoading}/></NavButton>
      </div>
      <div className="fixed top-4 right-4 z-[500] flex gap-3 items-center">
        <div className={`flex p-1 rounded-full border backdrop-blur-xl ${isRenoir ? 'bg-amber-950/40 border-amber-900/20' : 'bg-white/40 border-black/5'}`}>
          <button onClick={() => setUiLanguage(l => l === 'EN' ? 'RU' : 'EN')} className="w-8 h-8 rounded-full text-[9px] font-black">{uiLanguage}</button>
          <button onClick={() => setTheme(t => t === 'SUPREMATIST' ? 'IMPRESSIONIST' : 'SUPREMATIST')} className={`px-3 h-8 rounded-full text-[9px] font-black ${isRenoir ? 'bg-amber-700 text-white' : 'bg-black text-white'}`}>
            {theme === 'SUPREMATIST' ? 'Mode A' : 'Mode B'}
          </button>
        </div>
        <NavButton onClick={() => setShowHistory(true)}><Icons.History /></NavButton>
      </div>
    </>
  );

  const HistorySidebar = (
    <div className={`fixed inset-0 z-[1000] flex justify-end transition-all ${showHistory ? 'visible opacity-100' : 'invisible opacity-0'}`}>
      <div className={`fixed inset-0 bg-black/60 backdrop-blur-sm transition-opacity duration-300 ${showHistory ? 'opacity-100' : 'opacity-0'}`} onClick={() => setShowHistory(false)} />
      <div className={`relative z-[1010] w-full max-sm:max-w-full max-w-sm h-full p-6 md:p-12 shadow-2xl overflow-y-auto flex flex-col transition-transform duration-500 transform ${showHistory ? 'translate-x-0' : 'translate-x-full'} ${isRenoir ? 'bg-[#1e0a0a] text-amber-100 border-l border-amber-900/10' : 'bg-white text-black border-l border-black/5'}`}>
         <div className="flex justify-between items-center mb-10">
            <h2 className="text-xl md:text-2xl font-black uppercase tracking-tighter">{t.history}</h2>
            <button onClick={() => setShowHistory(false)} className="p-2 hover:rotate-90 transition-transform bg-current/5 rounded-full"><Icons.Close /></button>
         </div>
         <div className="space-y-6 flex-1">
            {history.length === 0 ? (
              <div className="text-center py-24 opacity-20 text-[10px] font-black uppercase tracking-widest">{t.voidEmpty}</div>
            ) : history.map(item => (
              <button key={item.id} onClick={() => { stopAudio(); setState({ ...state, status: 'REVEALED', response: item.response, query: item.query, logicScore: item.logicScore, chaosScore: item.chaosScore }); setShowHistory(false); }} className="block w-full text-left p-6 border border-current/10 rounded-3xl hover:bg-current/5 hover:border-current/20 transition-all group active:scale-95 shadow-sm">
                <div className="text-[9px] opacity-40 mb-2 font-black tracking-widest uppercase flex justify-between items-center">
                  <span>{new Date(item.timestamp).toLocaleTimeString()}</span>
                  <span className="opacity-0 group-hover:opacity-100 transition-opacity">→</span>
                </div>
                <div className="text-base font-bold uppercase truncate">{item.query}</div>
                {item.response.isDaily && <div className="mt-2 text-[7px] font-black uppercase tracking-[0.3em] text-amber-500 flex items-center gap-1"><Icons.Sparkle /> Daily Artifact</div>}
              </button>
            ))}
         </div>
      </div>
    </div>
  );

  if (state.status === 'ERROR') return (
    <div className={`h-screen flex flex-col items-center justify-center p-8 text-center ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
       <h1 className="text-2xl font-black uppercase mb-4 tracking-tighter">Paradox Encountered</h1>
       <p className="text-xs opacity-60 mb-8 max-w-xs mx-auto">{state.error}</p>
       <button onClick={() => setState(s => ({ ...s, status: 'IDLE' }))} className="px-8 py-3 border border-current font-black uppercase text-[10px] rounded-full">Recalibrate</button>
    </div>
  );

  if (state.status === 'THINKING') return <LoadingScreen theme={theme} language={uiLanguage} />;

  if (state.status === 'REVEALED' && state.response) {
    const r = state.response;
    const imageSrc = r.base64Image ? `data:image/png;base64,${r.base64Image}` : r.imageUrl;
    const perspectivesList = [
      { id: 'psychoanalysis', label: t.frameworks.PSYCHOANALYSIS },
      { id: 'gestalt', label: t.frameworks.GESTALT },
      { id: 'russian_philosophy', label: t.frameworks.RUSSIAN },
      { id: 'german_philosophy', label: t.frameworks.GERMAN },
      { id: 'existential', label: t.frameworks.EXISTENTIAL },
      { id: 'theological', label: t.frameworks.THEOLOGICAL },
      { id: 'buddhist', label: t.frameworks.BUDDHIST },
      { id: 'post_modern', label: t.frameworks.POST_MODERN },
    ];

    return (
      <div className={`min-h-screen pt-24 pb-12 px-6 md:px-8 overflow-y-auto ${isRenoir ? 'bg-[#0f0505] text-amber-100 font-serif' : 'bg-white text-black font-sans'}`}>
        {GlobalUI}
        {HistorySidebar}
        <div ref={captureRef} className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-16 items-start">
          <div className="flex flex-col items-center lg:sticky lg:top-24 order-1">
            <div className="w-full max-w-[280px] md:max-w-sm">
              <RatioIndicator logicScore={state.logicScore} chaosScore={state.chaosScore} category={r.category as any} theme={theme} language={uiLanguage} />
              <div className="relative group">
                <div className={`w-full aspect-square border overflow-hidden shadow-2xl ${isRenoir ? 'border-amber-900/20 rounded-3xl' : 'border-black/10'}`}>
                  {isImageLoading && <div className="absolute inset-0 bg-black/40 backdrop-blur-sm z-10 flex items-center justify-center text-white text-[10px] uppercase font-black tracking-widest">Re-imagining...</div>}
                  <img src={imageSrc} className="w-full h-full object-cover" crossOrigin="anonymous" alt="Oracle Visual" />
                </div>
                <div className={`absolute bottom-4 left-4 right-4 p-2 backdrop-blur-md border border-white/10 rounded-lg text-[8px] font-black uppercase tracking-widest text-center shadow-lg opacity-80 group-hover:opacity-100 transition-opacity ${isRenoir ? 'bg-amber-950/60 text-amber-100' : 'bg-white/60 text-black'}`}>
                  {r.imageStyleLabel || 'ABSTRACT'} — {theme === 'SUPREMATIST' ? 'MODE A' : 'MODE B'}
                </div>
                {r.isDaily && (
                  <div className={`absolute -top-3 -right-3 px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2 border ${isRenoir ? 'bg-amber-100 text-amber-900 border-amber-900' : 'bg-black text-white border-white'}`}>
                    <Icons.Sparkle /> {t.dailyContemplation}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center lg:items-start order-2 w-full max-w-[480px] lg:max-w-none mx-auto">
            {/* Title Block */}
            <h1 className="text-xl md:text-3xl font-black uppercase tracking-tighter leading-tight whitespace-pre-wrap text-center lg:text-left mb-6">
              {r.title}
            </h1>

            {/* Comparison Split Screen or Single Verdict */}
            {r.type === 'COMPARISON' && r.comparison ? (
              <div className="w-full space-y-4 mb-6 transition-all duration-700">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className={`p-4 border-2 ${r.comparison.winner === 'A' ? 'border-red-600' : 'border-current/10'} rounded-2xl`}>
