const textModel = "gemini-3-flash-preview"; 

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) return jsonMatch[0];
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```json\s*/, '').replace(/```$/, '');
  return cleaned.trim();
}

const perspectiveSchema = {
  type: Type.OBJECT,
  properties: {
    verdict: { type: Type.STRING },
    analysis: { type: Type.STRING }
  },
  required: ["verdict", "analysis"]
};

const oracleResponseSchema = {
  type: Type.OBJECT,
  properties: {
    type: { type: Type.STRING },
    category: { type: Type.STRING },
    title: { type: Type.STRING },
    verdict: { type: Type.STRING },
    detailedAnalysis: { type: Type.STRING },
    perspectives: {
      type: Type.OBJECT,
      properties: {
        psychoanalysis: perspectiveSchema,
        gestalt: perspectiveSchema,
        russian_philosophy: perspectiveSchema,
        german_philosophy: perspectiveSchema,
        existential: perspectiveSchema,
        theological: perspectiveSchema,
        buddhist: perspectiveSchema,
        post_modern: perspectiveSchema
      }
    },
    sources: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          uri: { type: Type.STRING }
        }
      }
    },
    comparison: {
      type: Type.OBJECT,
      properties: {
        optionA: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            score: { type: Type.NUMBER }
          }
