const TextBlock: React.FC<{ text?: string; light?: boolean }> = ({ text, light }) => {
  if (!text) return null;
  // Handle newlines robustly to ensure paragraph breaks render correctly
  const paragraphs = text.split(/\n+/).map(p => p.trim()).filter(Boolean);
  return (
    <div className="space-y-6">
      {paragraphs.map((p, i) => (
        <p key={i} className={`text-base md:text-lg leading-relaxed text-justify font-light ${light ? 'text-white opacity-90' : 'opacity-90'}`}>
          {p}
        </p>
      ))}
    </div>
  );
};

