/**
 * Pollinations Text Fallback with Depth Requirements
 */
async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<string> {
    const prompt = `You are the Oracle of Chance, a decisive advisor. 
    Question: "${query}". 
    Chaos Score: ${chaosScore}/100. 
    Logic Score: ${100 - chaosScore}/100.

    If Chaos is high, be radical, disruptive, and risk-oriented. 
    If Logic is high, be systemic, analytical, and cautious.

    Respond STRICTLY in JSON. Include ALL keys: "psychoanalysis", "gestalt", "russian_philosophy", "german_philosophy", "existential", "theological", "buddhist", "post_modern".
    Each perspective must have:
    1. "verdict": A precise advice or answer.
    2. "analysis": 4-5 dense paragraphs of philosophical reasoning.
    3. "sourceQuery": A search query related to this specific claim.

    detailedAnalysis must be 8-10 dense paragraphs. 
    Winner (A or B) must be declared if comparison.
    Language: ${language === 'RU' ? 'Russian' : 'English'}. No markdown.`;

    try {
        const response = await fetch(`https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true`);
        return await response.text();
    } catch (e) {
        throw new Error("Void Paradox.");
    }
}

function determineSubStyle(response: OracleResponse, chaosScore: number, mode: 'SUPREMATIST' | 'IMPRESSIONIST'): string {
    const titleLower = (response.title || "").toLowerCase();
    const isMedia = response.category === 'MEDIA' || titleLower.includes('movie');
    if (isMedia) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (mode === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: prompt }] },
            config: { imageConfig: { aspectRatio: "1:1" } }
        });
        const candidate = response.candidates?.[0];
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) return { image: part.inlineData.data, isFallback: false };
            }
        }
    } catch (e) { console.warn("Image Gemini quota reached"); }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
            }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
            const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), context, 24000, 1);
            const source = context.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(context.destination);
            source.start();
            return { context, source };
        }
    } catch (e) { console.error(e); }
    throw new Error("Audio failed");
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const payload = JSON.parse(JSON.stringify(data));
    const originalImage = payload.base64Image;
    const originalUrl = payload.imageUrl;
    delete payload.base64Image;
    delete payload.imageUrl;

    try {
        const response = await ai.models.generateContent({
            model: textModel,
            contents: `Translate this JSON into ${targetLang}. Preserve the original structure exactly. JSON: ${JSON.stringify(payload)}`,
            config: { 
              responseMimeType: "application/json",
              responseSchema: oracleResponseSchema
            }
        });
        const parsed = JSON.parse(cleanJsonResponse(response.text || "{}"));
        return { ...parsed, base64Image: originalImage, imageUrl: originalUrl, language: targetLang, isFallback: data.isFallback };
    } catch (e) {
        return { ...data, language: targetLang };
    }
};

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let isTextFallback = false;
  let responseText = "";
  let fetchedSources: OracleSource[] = [];

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: query,
      config: { 
        systemInstruction: `You are The Oracle of Chance, a decisive advisor. 
        Chaos Score: ${chaosPercentage}/100. 
        Logic Score: ${100 - chaosPercentage}/100.

        ADVICE PROTOCOL:
        - If Chaos is high (>60): Advice must be radical, transformative, risk-positive, and disruptive.
        - If Logic is high (>60): Advice must be systemic, safety-first, conservative, and analytical.
        - Questions like "Should I quit my job?" or future predictions MUST result in a definitive "YES" or "NO" path within each philosophical school's analysis.

        CRITICAL FORMATTING:
        - All analysis must be divided into 4-5 dense paragraphs per perspective using double newlines (\\n\\n). 
        - detailedAnalysis must be 8-10 dense paragraphs.
        - Each perspective must include a 'sourceQuery' for users to verify the claim.
        - Respond strictly in JSON.
        - Language: ${language}.`,
        tools: [{ googleSearch: {} }], 
        temperature: (chaosPercentage / 100) + 0.1,
        responseMimeType: "application/json",
        responseSchema: oracleResponseSchema
      },
    });
    responseText = response.text || "{}";
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Link", uri: chunk.web.uri }));
    }
  } catch (e) {
    isTextFallback = true;
    responseText = await fallbackTextGeneration(query, language, chaosPercentage);
  }

  try {
    const parsed = JSON.parse(cleanJsonResponse(responseText)) as OracleResponse;
    const subStyle = determineSubStyle(parsed, chaosPercentage, artStyle);
    parsed.imageStyleLabel = subStyle.replace('_', '-');
    const imgResult = await generateImageWithFallback(`Artistic interpretation of "${parsed.title}" in style of ${subStyle}. atmosphere.`);

    return { 
      ...parsed, 
      base64Image: imgResult.image, 
      imageUrl: imgResult.url, 
      sources: fetchedSources.length > 0 ? fetchedSources : (parsed.sources || []),
      language,
      isFallback: isTextFallback || imgResult.isFallback
    };
  } catch (e) {
    throw new Error("Revelation Parsing Error.");
  }
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = determineSubStyle(response, chaosScore, artStyle);
    const result = await generateImageWithFallback(`Artistic interpretation of "${response.title}" in style of ${subStyle}. atmosphere.`);
    return { image: result.image, url: result.url, label: subStyle.replace('_', '-'), isFallback: result.isFallback };
};

