              <button type="button" onClick={handleDailyOracle} className={`flex items-center gap-2 px-5 py-2 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest border-2 transition-all shadow-xl border-amber-500/50 text-amber-600 hover:bg-amber-500 hover:text-white`}>
                <Icons.Sparkle /> {t.daily}
              </button>
            </div>

            <div className={`w-full max-w-[240px] md:max-w-[280px] overflow-hidden transition-all duration-500 ease-in-out ${isManual ? 'max-h-40 opacity-100 mb-2' : 'max-h-0 opacity-0 pointer-events-none'}`}>
              <div className="p-4 bg-current/5 rounded-[32px] border border-current/10 space-y-4 backdrop-blur-xl">
                <div className="flex justify-between text-[8px] font-black uppercase tracking-widest">
                   <span className="opacity-40">{t.logic}</span>
                   <span className="text-red-500">{t.chaos}</span>
                </div>
                <input type="range" min="0" max="100" value={state.chaosScore} onChange={e => { const c = parseInt(e.target.value); setState(s => ({ ...s, chaosScore: c, logicScore: 100 - c })); }} className="w-full h-1 bg-current/10 rounded-full appearance-none cursor-pointer accent-red-600" />
              </div>
            </div>

            <button type="submit" className={`w-24 h-24 md:w-28 md:h-28 font-black uppercase transition-all hover:scale-105 active:scale-95 shadow-2xl flex items-center justify-center group ${theme === 'SUPREMATIST' ? 'rounded-none rotate-3 hover:rotate-0' : 'rounded-[40px] md:rounded-[50px] scale-95 hover:scale-100'} ${isRenoir ? 'bg-amber-900 text-white' : 'bg-black text-white'}`}>
              <span className={`tracking-[0.1em] group-hover:tracking-[0.2em] transition-all leading-tight text-center px-4 ${uiLanguage === 'RU' ? 'text-[10px] md:text-[12px]' : 'text-xs md:text-sm'}`}>{t.ask}</span>
            </button>
          </div>

          <div className="flex flex-wrap justify-center gap-2 max-w-sm md:max-w-md mx-auto opacity-20">
            {suggestions.map(s => (
              <button key={s} type="button" onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} className="px-3 py-1 text-[8px] border border-current/20 rounded-full font-black hover:opacity-100 transition-all">
                {s}
              </button>
            ))}
          </div>
        </form>
      </div>

      <footer className="absolute bottom-6 text-[8px] opacity-10 tracking-[1em] font-black select-none uppercase">
        {t.footer}
      </footer>
    </div>
  );
};

