function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  // Pre-clean escaped newlines that the AI sometimes literalizes
  let cleaned = text.replace(/\\n/g, '\n');
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      // Test if it's valid JSON after extraction
      const match = jsonMatch[0];
      JSON.parse(match);
      return match;
    } catch (e) {
      // If it fails, try to fix common JSON issues like trailing commas
      return jsonMatch[0].replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
    }
  }
  return "{}";
}

