import { GoogleGenAI, Modality, Type } from "@google/genai";
import { OracleResponse, OracleSource } from "../types";

declare var process: {
  env: {
    API_KEY: string;
  };
};

const textModel = "gemini-3-flash-preview"; 

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Robustly extracts and sanitizes a JSON string from AI output.
 * Fixes "Bad control character" errors by escaping raw newlines and tabs 
 * that appear inside string literals.
 */
function cleanJsonResponse(text: string): string {
  if (!text) return "{}";

  // 1. Extract the actual JSON block
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start === -1 || end === -1) return "{}";
  const jsonPart = text.substring(start, end + 1);

  // 2. Character-by-character scan to escape control chars inside string values
  let sanitized = "";
  let insideString = false;
  let escaped = false;

  for (let i = 0; i < jsonPart.length; i++) {
    const char = jsonPart[i];

    if (char === '"' && !escaped) {
      insideString = !insideString;
      sanitized += char;
    } else if (insideString) {
      // Handle control characters that are illegal in raw JSON strings
      if (char === '\n') sanitized += "\\n";
      else if (char === '\r') sanitized += "\\r";
      else if (char === '\t') sanitized += "\\t";
      else if (char.charCodeAt(0) < 32) {
        // Strip other non-printable control characters
        continue;
      } else {
        sanitized += char;
        // Track escape state to properly identify the end of a string
        if (char === '\\') escaped = !escaped;
        else escaped = false;
      }
    } else {
      sanitized += char;
      escaped = false;
    }
  }

  return sanitized;
}

const perspectiveSchema = {
  type: Type.OBJECT,
  properties: {
    verdict: { type: Type.STRING },
    analysis: { type: Type.STRING },
    sourceQuery: { type: Type.STRING, description: "A search query for study." }
  },
  required: ["verdict", "analysis", "sourceQuery"]
};

const oracleResponseSchema = {
  type: Type.OBJECT,
  properties: {
    type: { type: Type.STRING },
    category: { type: Type.STRING },
    title: { type: Type.STRING },
    verdict: { type: Type.STRING },
    detailedAnalysis: { type: Type.STRING },
    perspectives: {
      type: Type.OBJECT,
      properties: {
        psychoanalysis: perspectiveSchema,
        gestalt: perspectiveSchema,
        russian_philosophy: perspectiveSchema,
        german_philosophy: perspectiveSchema,
        existential: perspectiveSchema,
        theological: perspectiveSchema,
        buddhist: perspectiveSchema,
        post_modern: perspectiveSchema
      }
    },
    sources: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          uri: { type: Type.STRING }
        }
      }
    },
    comparison: {
      type: Type.OBJECT,
      properties: {
        optionA: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            score: { type: Type.NUMBER }
          }
        },
        optionB: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            score: { type: Type.NUMBER }
          }
        },
        winner: { type: Type.STRING }
      }
    }
  },
  required: ["type", "category", "title", "verdict", "detailedAnalysis", "perspectives"]
};

async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<string> {
    const prompt = `Act as The Oracle of Chance. User asks: "${query}". 
    Chaos level: ${chaosScore}/100. Logic level: ${100 - chaosScore}/100.

    INSTRUCTIONS:
    - RESPOND ONLY WITH VALID JSON.
    - NEVER include raw newlines inside a string; use "\\n" instead.
    - "detailedAnalysis" must be exactly 6-8 dense paragraphs.
    - "perspectives" must contain ALL keys: psychoanalysis, gestalt, russian_philosophy, german_philosophy, existential, theological, buddhist, post_modern.
    - Language: ${language === 'RU' ? 'Russian' : 'English'}.`;

    try {
        const response = await fetch(`https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true`);
        return await response.text();
    } catch (e) {
        throw new Error("Void Paradox.");
    }
}

function determineSubStyle(response: OracleResponse, chaosScore: number, mode: 'SUPREMATIST' | 'IMPRESSIONIST'): string {
    const titleLower = (response.title || "").toLowerCase();
    const isMedia = response.category === 'MEDIA' || titleLower.includes('movie');
    if (isMedia) return chaosScore <= 50 ? (mode === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (mode === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "1:1" } }
        });
        const candidate = response.candidates?.[0];
        if (candidate?.content?.parts) {
          for (const part of candidate.content.parts) {
            if (part.inlineData) return { image: part.inlineData.data, isFallback: false };
          }
        }
    } catch (e) { console.warn("Image Gemini failed"); }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: "gemini-2.5-flash-preview-tts",
          contents: [{ parts: [{ text }] }],
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
          }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
          const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
          const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), context, 24000, 1);
          const source = context.createBufferSource();
          source.buffer = audioBuffer;
          source.connect(context.destination);
          source.start();
          return { context, source };
        }
    } catch (e) { console.error(e); }
    throw new Error("Audio failed");
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const payload = JSON.parse(JSON.stringify(data));
    const originalImage = payload.base64Image;
    const originalUrl = payload.imageUrl;
    delete payload.base64Image;
    delete payload.imageUrl;

    try {
        const response = await ai.models.generateContent({
          model: textModel,
          contents: `Translate this JSON into ${targetLang}. Preserve all paragraph markers. JSON: ${JSON.stringify(payload)}`,
          config: { 
            responseMimeType: "application/json",
            responseSchema: oracleResponseSchema
          }
        });
        const parsed = JSON.parse(cleanJsonResponse(response.text || "{}"));
        return { ...parsed, base64Image: originalImage, imageUrl: originalUrl, language: targetLang, isFallback: data.isFallback };
    } catch (e) {
        return { ...data, language: targetLang };
    }
};

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let isTextFallback = false;
  let responseText = "";
  let fetchedSources: OracleSource[] = [];

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: [{ parts: [{ text: query }] }],
      config: { 
        systemInstruction: `You are The Oracle of Chance. Chaos: ${chaosPercentage}%. Logic: ${100 - chaosPercentage}%.
        - Respond as a definitive advisor.
        - NEVER include raw newlines inside string values in your JSON; always use "\\n".
        - Use "detailedAnalysis" for 6-8 dense paragraphs.
        - Each of the 8 perspectives must have 3-4 dense paragraphs.
        - Respond strictly in the provided JSON schema.`,
        tools: [{ googleSearch: {} }], 
        temperature: Math.min(1.0, (chaosPercentage / 100) + 0.1),
        responseMimeType: "application/json",
        responseSchema: oracleResponseSchema
      },
    });
    responseText = response.text || "{}";
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Evidence", uri: chunk.web.uri }));
    }
  } catch (e) {
    isTextFallback = true;
    responseText = await fallbackTextGeneration(query, language, chaosPercentage);
  }

  try {
    const rawParsed = JSON.parse(cleanJsonResponse(responseText));
    const parsed = {
      type: 'SINGLE',
      perspectives: {},
      sources: [],
      detailedAnalysis: "The transmission was interrupted.",
      ...rawParsed
    } as OracleResponse;

    const subStyle = determineSubStyle(parsed, chaosPercentage, artStyle);
    parsed.imageStyleLabel = subStyle.replace('_', '-');
    const imgResult = await generateImageWithFallback(`Interpretation of "${parsed.title || query}" in style of ${subStyle}. Dramatic lighting.`);

    return { 
      ...parsed, 
      base64Image: imgResult.image, 
      imageUrl: imgResult.url, 
      sources: fetchedSources.length > 0 ? fetchedSources : (parsed.sources || []),
      language,
      isFallback: isTextFallback || imgResult.isFallback
    };
  } catch (e) {
    console.error("Critical parse error:", e);
    throw new Error("Revelation Parsing Error. The void is unstable.");
  }
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = determineSubStyle(response, chaosScore, artStyle);
    const result = await generateImageWithFallback(`Interpretation of "${response.title}" in style of ${subStyle}.`);
    return { image: result.image, url: result.url, label: subStyle.replace('_', '-'), isFallback: result.isFallback };
};

