async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<string> {
    const keys = ["title", "verdict", "detailedAnalysis", "category", "perspectives"];
    const perspectiveKeys = ["psychoanalysis", "gestalt", "russian_philosophy", "german_philosophy", "existential", "theological", "buddhist", "post_modern"];

    const prompt = `Act as The Oracle of Chance. Entscheidung for: "${query}". Chaos: ${chaosScore}%. 
    You must return a high-quality philosophical decision.

    CRITICAL: Output ONLY a JSON object. No markdown, no preamble. 
    REQUIRED FIELDS:
    - "title": A poetic title for this revelation.
    - "verdict": A short (3-5 words) decisive answer.
    - "detailedAnalysis": A long (600+ words) deep explanation split into paragraphs with "\\n\\n".
    - "category": Choose one: LIFE, RELATIONAL, KNOWLEDGE, FUTURE, TECH.
    - "perspectives": An object containing keys: ${perspectiveKeys.join(", ")}. 
