const TextBlock: React.FC<{ text?: string; light?: boolean; dropCap?: boolean; isRenoir?: boolean }> = ({ text, light, dropCap, isRenoir }) => {
  if (!text) return null;
  const cleanedText = text.replace(/\\n/g, '\n');

  const segments = cleanedText.split(/\n+/).map(p => p.trim()).filter(Boolean);

  const finalParagraphs: string[] = [];
  segments.forEach(segment => {
    if (segment.length > 600) {
      const subParagraphs = segment.match(/[^.!?]+[.!?]+(?:\s|$)/g);
      if (subParagraphs && subParagraphs.length > 3) {
        for (let i = 0; i < subParagraphs.length; i += 3) {
          finalParagraphs.push(subParagraphs.slice(i, i + 3).join("").trim());
        }
      } else {
        finalParagraphs.push(segment);
      }
    } else {
      finalParagraphs.push(segment);
    }
  });

  return (
    <div className="space-y-8">
      {finalParagraphs.map((p, i) => {
        if (dropCap && p.length > 0) {
          const firstChar = p.charAt(0);
          const rest = p.substring(1);
          return (
            <p key={i} className={`text-base md:text-lg leading-relaxed text-justify font-light ${light ? 'text-white opacity-90' : 'opacity-90'}`}>
              <span className={`float-left text-6xl md:text-7xl font-black mr-4 mt-1 leading-[0.75] ${isRenoir ? 'font-serif text-amber-500' : 'font-sans text-red-600'}`}>
                {firstChar}
              </span>
              {rest}
            </p>
          );
        }
        return (
          <p key={i} className={`text-base md:text-lg leading-relaxed text-justify font-light ${light ? 'text-white opacity-90' : 'opacity-90'}`}>
            {p}
          </p>
        );
      })}
    </div>
  );
};

