  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let responseData: any = null;
  let fetchedSources: OracleSource[] = [];
  let isFallback = false;
  const randomSeed = Math.floor(Math.random() * 1000000);

  // Tier 1: Gemini with Search
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: query }] }],
      config: { 
        systemInstruction: `You are The Oracle of Chance. Chaos level: ${chaosPercentage}%. 
        - Respond definitively as a wise advisor.
        - YOUR VERDICT MUST BE HEAVILY INFLUENCED BY THE CHAOS SCORE.
        - High Chaos (70-100%): Be radical, poetic, slightly unhinged, suggesting bold risks.
        - Low Chaos (0-30%): Be stoic, practical, safe, and logical.
        - If query is a comparison (A vs B), set type: "COMPARISON" and fill "comparison" object.
        - detailedAnalysis: 6 dense paragraphs of ontological core.
        - perspectives: ALL 8 philosophers. Each philosopher's verdict must be a meaningful 1-3 word summary.
        - NEVER include raw newlines inside JSON string values; use "\\n".
        - Return Strict JSON.`,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        seed: randomSeed
      },
    });
    responseData = cleanJsonResponse(response.text || "{}");
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ 
          title: chunk.web.title || "Evidence", 
          uri: chunk.web.uri || "#" 
        }));
    }
  } catch (e) {
    // Tier 2: Gemini WITHOUT Search
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: query }] }],
        config: { 
          systemInstruction: `Oracle of Chance. Chaos: ${chaosPercentage}%. Response: Strict JSON with 8 perspectives. High chaos scores should lead to unconventional, risky advice.`,
          responseMimeType: "application/json",
          seed: randomSeed
        },
      });
      responseData = cleanJsonResponse(response.text || "{}");
    } catch (e2) {
      // Tier 3: Pollinations Backup
      isFallback = true;
      responseData = await fallbackTextGeneration(query, language, chaosPercentage);
    }
  }

  // Healing Stage
  const finalizedTextData = await healResponse(responseData || {}, query, language, chaosPercentage);

  // Image Generation
  const subStyle = (function() {
    const titleLower = (finalizedTextData.title || "").toLowerCase();
    if (finalizedTextData.category === 'MEDIA' || titleLower.includes('movie')) return chaosPercentage <= 50 ? (artStyle === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
