/**
 * Heals a potentially broken OracleResponse by synthesizing missing parts.
 */
async function healResponse(data: any, query: string, language: 'EN' | 'RU', chaosScore: number): Promise<OracleResponse> {
  const isComparisonQuery = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ');

  const healed: any = {
    type: data.type || (isComparisonQuery ? 'COMPARISON' : 'SINGLE'),
    title: data.title || query.substring(0, 40) + "...",
    verdict: data.verdict || "",
    detailedAnalysis: data.detailedAnalysis || "",
    category: data.category || "LIFE",
    perspectives: data.perspectives || {},
    sources: data.sources && Array.isArray(data.sources) && data.sources.length > 0 ? data.sources : [
      { title: "Wikipedia Archive", uri: `https://en.wikipedia.org/wiki/Special:Search?search=${encodeURIComponent(query)}` },
      { title: "Philosophical Inquiry", uri: `https://plato.stanford.edu/search/searcher.py?query=${encodeURIComponent(query)}` }
    ]
  };

  // CORE HEALING
  if (!healed.verdict || !healed.detailedAnalysis || healed.detailedAnalysis.length < 50) {
    const corePrompt = `As the Oracle, provide a FINAL DECISIVE VERDICT and a 6-paragraph ONTOLOGICAL CORE analysis for the query: "${query}". 
    Chaos level: ${chaosScore}%. Higher chaos leads to wilder, more entropic results. 
    Language: ${language === 'RU' ? 'Russian' : 'English'}. 
    Return JSON: {"verdict": "3 words", "detailedAnalysis": "6 long paragraphs"}. 
    NO FLUFF. BE DEEP.`;

    try {
      const extraRaw = await callPollinations(corePrompt, 'openai');
      const extraData = cleanJsonResponse(extraRaw);
      healed.verdict = extraData.verdict || "THE PATH IS CHOSEN";
      healed.detailedAnalysis = extraData.detailedAnalysis || "The transmission from the void was successfully established. Your fate is inscribed in the patterns of chance.";
    } catch (e) {
      healed.verdict = healed.verdict || "CHANCE REMAINS OBSCURE";
      healed.detailedAnalysis = healed.detailedAnalysis || "The logic patterns within the void reached a state of quantum superposition.";
    }
  }

  // Comparison Healing
  if (healed.type === 'COMPARISON') {
    if (!data.comparison || !data.comparison.optionA || !data.comparison.winner) {
      const parts = query.split(/ vs | or /i);
      const compPrompt = `As the Oracle, compare "${parts[0]}" vs "${parts[1]}". 
      Determine a winner and provide descriptions. Chaos: ${chaosScore}%. 
      Return JSON: {"optionA": {"title": "...", "description": "...", "score": 70}, "optionB": {"title": "...", "description": "...", "score": 30}, "winner": "A"}. 
      Language: ${language === 'RU' ? 'Russian' : 'English'}.`;

      try {
        const compRaw = await callPollinations(compPrompt, 'openai');
        healed.comparison = cleanJsonResponse(compRaw);
      } catch (e) {
        healed.comparison = {
          optionA: { title: parts[0]?.trim() || "Path A", description: "This path holds a certain resonance with the current logical structure.", score: 55 },
          optionB: { title: parts[1]?.trim() || "Path B", description: "This path introduces a higher degree of entropy into your life.", score: 45 },
          winner: Math.random() > 0.5 ? 'A' : 'B'
        };
      }
    } else {
      healed.comparison = data.comparison;
    }
  }

  // Perspective Healing
  const missingKeys = PERSPECTIVE_KEYS.filter(k => !healed.perspectives[k]);
  if (missingKeys.length > 0) {
    const healPrompt = `Generate philosophical perspectives for: "${query}". 
    Target keys: ${missingKeys.join(', ')}. Return ONLY JSON. 
    Language: ${language === 'RU' ? 'Russian' : 'English'}. 
    Each perspective MUST HAVE: {"verdict": "A meaningful 1-3 word summary", "analysis": "3-paragraph philosophical text"}.`;

    try {
      const extraRaw = await callPollinations(healPrompt, 'openai');
      const extraData = cleanJsonResponse(extraRaw);
      if (extraData && typeof extraData === 'object') {
        Object.assign(healed.perspectives, extraData);
      }
    } catch (e) {}

    missingKeys.forEach(k => {
      if (!healed.perspectives[k]) {
        healed.perspectives[k] = {
          verdict: "INDETERMINATE",
          analysis: `The specific philosophical resonance for ${k.replace('_', ' ')} was absorbed by the background radiation of the void.`
        };
      }
    });
  }

  return healed as OracleResponse;
}

