/**
 * Heals a potentially broken OracleResponse by synthesizing missing parts.
 */
async function healResponse(data: any, query: string, language: 'EN' | 'RU', chaosScore: number): Promise<OracleResponse> {
  const isComparisonQuery = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');

  const healed: any = {
    type: data.type || (isComparisonQuery ? 'COMPARISON' : 'SINGLE'),
    title: data.title || query.substring(0, 40) + "...",
    verdict: data.verdict || "",
    detailedAnalysis: data.detailedAnalysis || "",
    category: data.category || "LIFE",
    perspectives: data.perspectives || {},
    sources: data.sources && Array.isArray(data.sources) && data.sources.length > 0 ? data.sources : [
      { title: "Universal Knowledge", uri: `https://en.wikipedia.org/wiki/Special:Search?search=${encodeURIComponent(query)}` },
      { title: "Deep Inquiry", uri: `https://plato.stanford.edu/search/searcher.py?query=${encodeURIComponent(query)}` }
    ]
  };

  // 1. Perspective Healing (Ensure all 8 exist)
  const missingKeys = PERSPECTIVE_KEYS.filter(k => !healed.perspectives[k]);
  if (missingKeys.length > 0) {
    const healPrompt = `Generate independent philosophical voices for: "${query}". 
    Target keys: ${missingKeys.join(', ')}. Return ONLY JSON. 
    ${isComparisonQuery ? 'Must vote "A" or "B"' : 'Must vote "YES" or "NO"'}.
    Each voice MUST HAVE: {"vote": "A/B or YES/NO", "verdict": "Summary", "analysis": "Detailed text"}.`;

    try {
      const extraRaw = await callPollinations(healPrompt, 'openai');
      const extraData = cleanJsonResponse(extraRaw);
      if (extraData && typeof extraData === 'object') {
        Object.assign(healed.perspectives, extraData);
      }
    } catch (e) {}

    missingKeys.forEach(k => {
      if (!healed.perspectives[k]) {
        healed.perspectives[k] = {
          vote: Math.random() > 0.5 ? (isComparisonQuery ? 'A' : 'YES') : (isComparisonQuery ? 'B' : 'NO'),
          verdict: "INDETERMINATE",
          analysis: "The specific resonance was lost."
        };
      }
    });
  }

  // 2. Exact Vote Tallying
  let votesA = 0;
  let votesB = 0;
  let votesYes = 0;
  let votesNo = 0;

  PERSPECTIVE_KEYS.forEach(key => {
    const p = healed.perspectives[key];
    if (!p) return;
    const v = String(p.vote || "").toUpperCase();

    // Check for A/B (Comparison)
    if (v === 'A' || v.includes('OPTION A') || v.includes('OPTIONA')) votesA++;
    else if (v === 'B' || v.includes('OPTION B') || v.includes('OPTIONB')) votesB++;

    // Check for YES/NO (Single)
    if (v === 'YES' || v.includes('FOR') || v.includes('TRUE')) votesYes++;
    else if (v === 'NO' || v.includes('AGAINST') || v.includes('FALSE')) votesNo++;
  });

  // 3. Final Comparison Construction
  if (healed.type === 'COMPARISON') {
    // If we have no comparison votes but we do have single-type votes, convert them
    if (votesA === 0 && votesB === 0 && (votesYes > 0 || votesNo > 0)) {
        votesA = votesYes;
        votesB = votesNo;
    }

    // Ensure we have exactly 8 votes for math consistency
    const total = votesA + votesB;
    if (total !== 8) {
        const diff = 8 - total;
        for (let i = 0; i < diff; i++) {
            if (Math.random() > 0.5) votesA++; else votesB++;
        }
    }

    const scoreA = Math.round((votesA / 8) * 100);
    const scoreB = 100 - scoreA;

    const parts = query.split(/ vs | or | или /i);

    healed.comparison = {
      optionA: { 
        title: data.comparison?.optionA?.title || parts[0]?.trim() || "Path A", 
        description: data.comparison?.optionA?.description || "A path defined by internal resonance.", 
        score: scoreA 
      },
      optionB: { 
        title: data.comparison?.optionB?.title || parts[1]?.trim() || "Path B", 
        description: data.comparison?.optionB?.description || "A path defined by external entropy.", 
        score: scoreB 
      },
      winner: votesA > votesB ? 'A' : (votesB > votesA ? 'B' : 'DRAW'),
      tally: `${votesA} vs ${votesB}`
    };
  }

  // 4. Detailed Analysis/Verdict Healing
  if (!healed.verdict || !healed.detailedAnalysis || healed.detailedAnalysis.length < 50) {
    const corePrompt = `As the Oracle, summarize these 8 philosophical voices into a FINAL VERDICT for "${query}". 
    Chaos: ${chaosScore}%. Tally: ${healed.type === 'COMPARISON' ? healed.comparison.tally : (votesYes + ' vs ' + votesNo)}.
    Return JSON: {"verdict": "Decisive summary", "detailedAnalysis": "6 paragraphs"}.`;

    try {
      const extraRaw = await callPollinations(corePrompt, 'openai');
      const extraData = cleanJsonResponse(extraRaw);
      healed.verdict = extraData.verdict || healed.verdict || "THE PATH IS CHOSEN";
      healed.detailedAnalysis = extraData.detailedAnalysis || healed.detailedAnalysis || "The void has spoken.";
    } catch (e) {}
  }

  return healed as OracleResponse;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { 
            imageConfig: { aspectRatio: "1:1" },
            seed: Math.floor(Math.random() * 1000000)
          }
        });
        const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
        if (part?.inlineData?.data) return { image: part.inlineData.data, isFallback: false };
    } catch (e) { 
        console.warn("Gemini Image Failed"); 
    }

    const seed = Math.floor(Math.random() * 1000000);
    return { 
      url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, 
      isFallback: true 
    };
}

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let responseData: any = null;
  let fetchedSources: OracleSource[] = [];
  let isFallback = false;
  const randomSeed = Math.floor(Math.random() * 1000000);

  // Tier 1: Gemini with Search
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: query }] }],
      config: { 
        systemInstruction: `You are The Oracle of Chance. 
        Council Algorithm:
        - 8 distinct philosophical VOICES (perspectives) must vote.
        - Comparison Query: Each voice MUST vote "A" or "B".
        - Single Query: Each voice MUST vote "YES" or "NO".
        - Chaos level is ${chaosPercentage}%.
        - Return Strict JSON.`,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        seed: randomSeed
      },
    });
    responseData = cleanJsonResponse(response.text || "{}");
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ 
          title: chunk.web.title || "Evidence", 
          uri: chunk.web.uri || "#" 
        }));
    }
  } catch (e) {
    // Tier 2: Gemini WITHOUT Search
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: query }] }],
        config: { 
          systemInstruction: `Oracle of Chance. Chaos: ${chaosPercentage}%. 8 voices. Strict voting logic.`,
          responseMimeType: "application/json",
          seed: randomSeed
        },
      });
      responseData = cleanJsonResponse(response.text || "{}");
    } catch (e2) {
      // Tier 3: Pollinations Backup
      isFallback = true;
      responseData = await fallbackTextGeneration(query, language, chaosPercentage);
    }
  }

  // Healing Stage
  const finalizedTextData = await healResponse(responseData || {}, query, language, chaosPercentage);

  // Image Generation
  const subStyle = (function() {
    const titleLower = (finalizedTextData.title || "").toLowerCase();
    if (finalizedTextData.category === 'MEDIA' || titleLower.includes('movie')) return chaosPercentage <= 50 ? (artStyle === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (artStyle === 'SUPREMATIST') return chaosPercentage < 40 ? 'CUBISM' : (chaosPercentage < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosPercentage < 40 ? 'IMPRESSIONISM' : (chaosPercentage < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
  })();

  const imgResult = await generateImageWithFallback(`Interpretation of "${finalizedTextData.title || "Revelation"}" in style of ${subStyle}. Dramatic composition.`);

  return { 
    ...finalizedTextData, 
    imageStyleLabel: subStyle.replace('_', '-'),
    base64Image: imgResult.image, 
    imageUrl: imgResult.url, 
    sources: fetchedSources.length > 0 ? fetchedSources : (finalizedTextData.sources || []),
    language,
    isFallback: isFallback || imgResult.isFallback
  };
};

