  const response = await fetch(url);
  if (!response.ok) throw new Error("Pollinations Service Error");
  return await response.text();
}

/**
 * Detects if the query requires a choice (Yes/No, A vs B).
 * Refined to treat simple phrases and titles as Inquiries.
 */
function isChoiceQuery(query: string): boolean {
  const q = query.toLowerCase().trim();

  // High-certainty decision markers
  const comparisonMarkers = [' vs ', ' or ', ' или '];
  const polarMarkers = [
    'should i', 'can i', 'must i', 'will i', 'is it', 'do i',
    'стоит ли', 'нужно ли', 'можно ли', 'будет ли', 'лучше', 'better'
  ];

  const hasComparison = comparisonMarkers.some(m => q.includes(m));
  const hasPolar = polarMarkers.some(m => q.includes(m));

  // If it's just a phrase (no question mark and no markers), it's definitely an inquiry
  if (!q.includes('?') && !hasComparison && !hasPolar) return false;

  // If it ends in a question mark, but starts with "what", "how", "who", "why", "where", it's likely an inquiry
  const inquiryStarters = ['what ', 'how ', 'why ', 'who ', 'where ', 'что ', 'как ', 'почему ', 'кто ', 'где '];
  if (inquiryStarters.some(s => q.startsWith(s))) return false;

  return hasComparison || hasPolar || q.endsWith('?');
}

async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<any> {
