            </button>
          </div>
          <div className="flex flex-wrap justify-center gap-2 max-w-sm md:max-w-md mx-auto opacity-60">
            {suggestions.map(s => (
              <button key={s} type="button" onClick={() => { if(inputRef.current) inputRef.current.value = s; runQuery(s); }} className={`px-4 py-1.5 text-[9px] font-black border-2 rounded-full transition-all hover:opacity-100 hover:scale-105 active:scale-95 whitespace-nowrap ${isRenoir ? 'border-amber-900/40 text-amber-100/70 hover:bg-amber-900/20' : 'border-black/30 text-black/80 hover:bg-black/5'}`}>
                {s}
              </button>
            ))}
          </div>
        </form>
      </div>
      <footer className="absolute bottom-6 text-[8px] opacity-10 tracking-[1em] font-black select-none uppercase">
        {t.footer}
      </footer>
    </div>
  );
};

