const PERSPECTIVE_KEYS = ["psychoanalysis", "gestalt", "russian_philosophy", "german_philosophy", "existential", "theological", "buddhist", "post_modern"];

function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): any {
  if (!text) return {};
  try {
    let jsonPart = text.trim();
    const start = jsonPart.indexOf('{');
    const end = jsonPart.lastIndexOf('}');
    if (start === -1 || end === -1) return {};
    jsonPart = jsonPart.substring(start, end + 1);

    let sanitized = "";
    let insideString = false;
    let escaped = false;
    for (let i = 0; i < jsonPart.length; i++) {
      const char = jsonPart[i];
      if (char === '"' && !escaped) {
        insideString = !insideString;
        sanitized += char;
      } else if (insideString) {
        if (char === '\n') sanitized += "\\n";
        else if (char === '\r') sanitized += "\\r";
        else if (char === '\t') sanitized += "\\t";
        else if (char.charCodeAt(0) < 32) continue;
        else {
          sanitized += char;
          escaped = char === '\\' ? !escaped : false;
        }
      } else {
        sanitized += char;
        escaped = false;
      }
    }
    return JSON.parse(sanitized);
  } catch (e) {
    console.warn("JSON Clean failed", e);
    return {};
  }
}

async function callPollinations(prompt: string, model: string = 'openai'): Promise<string> {
  const seed = Math.floor(Math.random() * 1000000);
  const url = `https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true&model=${model}&seed=${seed}`;
  const response = await fetch(url);
  if (!response.ok) throw new Error("Pollinations Service Error");
  return await response.text();
}

/**
 * Categorizes the query mode: DECISION, RECOMMENDATION, or INQUIRY.
 */
function getQueryMode(query: string): 'DECISION' | 'RECOMMENDATION' | 'INQUIRY' {
  const q = query.toLowerCase().trim();

  // Recommendation Markers (Expanded with superlatives)
  const recommendationMarkers = [
    'what should i', 'give me a', 'recommend', 'suggest', 'ideas for', 'what to', 'лучший', 'best', 'the most', 'top',
    'что мне', 'посоветуй', 'рекомендуй', 'идеи для', 'выбери для меня', 'choose for me'
  ];
  if (recommendationMarkers.some(m => q.includes(m))) return 'RECOMMENDATION';

  // Decision Markers (Choices)
  const comparisonMarkers = [' vs ', ' or ', ' или '];
  const polarMarkers = [
    'should i', 'can i', 'must i', 'will i', 'is it', 'do i',
    'стоит ли', 'нужно ли', 'можно ли', 'будет ли', 'лучше', 'better'
  ];
  const hasComparison = comparisonMarkers.some(m => q.includes(m));
  const hasPolar = polarMarkers.some(m => q.includes(m));

  if (hasComparison || hasPolar || (q.endsWith('?') && !q.includes('what') && !q.includes('how'))) return 'DECISION';

  return 'INQUIRY';
}

async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<any> {
    const mode = getQueryMode(query);
    const isComparison = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');

    const prompt = `Act as The Oracle. Process query: "${query}". Chaos: ${chaosScore}%. 
    YOU MUST RETURN A VALID JSON OBJECT. NO PREAMBLE. NO MARKDOWN.

    Mode: ${mode}
    If DECISION: Each of the 8 philosophers MUST VOTE ("A/B" or "YES/NO").
    If RECOMMENDATION: Each philosopher offers THEMES/VALUES they enjoy. The main Verdict gives a SPECIFIC ITEM.
    If INQUIRY: Each provides deep philosophical take on the concept.

    REQUIRED KEYS for 'perspectives': psychoanalysis, gestalt, russian_philosophy, german_philosophy, existential, theological, buddhist, post_modern.

    {
      "type": "${mode === 'RECOMMENDATION' ? 'RECOMMENDATION' : (isComparison ? 'COMPARISON' : 'SINGLE')}",
      "isDecision": ${mode !== 'INQUIRY'},
      "title": "...",
      "verdict": "Name a specific entity if Recommendation, else a summary.",
      "detailedAnalysis": "Large synthesis",
      "category": "LIFE",
      "perspectives": {
         "psychoanalysis": {"vote": "", "verdict": "Theme/Value", "analysis": "Deep take"},
         ... repeat for all 8 ...
      }
    }
    Language: ${language === 'RU' ? 'Russian' : 'English'}.`;

    try {
      const raw = await callPollinations(prompt, 'openai');
      return cleanJsonResponse(raw);
    } catch (e) {
      const raw = await callPollinations(prompt, 'mistral');
      return cleanJsonResponse(raw);
    }
}

async function healResponse(data: any, query: string, language: 'EN' | 'RU', chaosScore: number): Promise<OracleResponse> {
  const mode = getQueryMode(query);
  const isDecision = mode !== 'INQUIRY';
  const isComparisonQuery = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');

  const healed: any = {
    ...data,
    type: data.type || (mode === 'RECOMMENDATION' ? 'RECOMMENDATION' : (isComparisonQuery ? 'COMPARISON' : 'SINGLE')),
    isDecision,
    title: data.title || query.substring(0, 40) + "...",
    verdict: data.verdict || "",
    detailedAnalysis: data.detailedAnalysis || "",
    category: data.category || "LIFE",
    perspectives: data.perspectives || {},
    sources: data.sources && Array.isArray(data.sources) && data.sources.length > 0 ? data.sources : [
      { title: "Universal Knowledge", uri: `https://en.wikipedia.org/wiki/Special:Search?search=${encodeURIComponent(query)}` },
      { title: "Deep Inquiry", uri: `https://plato.stanford.edu/search/searcher.py?query=${encodeURIComponent(query)}` }
    ]
  };

  // Ensure all 8 perspectives are populated and HAVE VOTES if needed
  PERSPECTIVE_KEYS.forEach(k => {
    if (!healed.perspectives[k]) healed.perspectives[k] = {};
    const p = healed.perspectives[k];

    // Force vote if missing in Decision Mode
    if (mode === 'DECISION' && (!p.vote || p.vote === '')) {
      p.vote = Math.random() > 0.5 ? (isComparisonQuery ? 'A' : 'YES') : (isComparisonQuery ? 'B' : 'NO');
    }

    if (!p.analysis || p.analysis.length < 50) {
      const philosopherName = k.replace('_', ' ').toUpperCase();
      p.verdict = p.verdict || (mode === 'RECOMMENDATION' ? "SYNERGY" : "REFLECTION");
      p.analysis = `The ${philosopherName} perspective on "${query}" suggests a deep alignment with the core revelation. Through this lens, the chaos of choice is resolved by acknowledging the underlying ${mode === 'RECOMMENDATION' ? 'desire for thematic resonance' : 'ontological structure'} present in the void. ${healed.detailedAnalysis.substring(0, 200)}...`;
    }
  });

  if (mode === 'DECISION') {
    let votesA = 0; let votesB = 0; let votesYes = 0; let votesNo = 0;
    Object.values(healed.perspectives).forEach((p: any) => {
      const v = String(p.vote || "").toUpperCase();
      if (v === 'A' || v.includes('OPTION A')) votesA++;
      else if (v === 'B' || v.includes('OPTION B')) votesB++;
      else if (v === 'YES' || v.includes('FOR')) votesYes++;
      else if (v === 'NO' || v.includes('AGAINST')) votesNo++;
    });

    if (healed.type === 'COMPARISON') {
      const total = votesA + votesB || 8;
      const scoreA = Math.round((votesA / total) * 100);
      const scoreB = 100 - scoreA;
      const parts = query.split(/ vs | or | или /i);
      healed.comparison = {
        optionA: { title: data.comparison?.optionA?.title || parts[0]?.trim() || "Path A", description: data.comparison?.optionA?.description || "Initial path.", score: scoreA },
        optionB: { title: data.comparison?.optionB?.title || parts[1]?.trim() || "Path B", description: data.comparison?.optionB?.description || "Secondary path.", score: scoreB },
        winner: votesA > votesB ? 'A' : (votesB > votesA ? 'B' : 'DRAW'),
        tally: `${votesA} vs ${votesB}`
      };
    } else {
      healed.tally = `${votesYes} vs ${votesNo}`;
      healed.verdict = `${healed.verdict} [${votesYes} ${language === 'RU' ? 'ЗА' : 'YES'} / ${votesNo} ${language === 'RU' ? 'ПРОТИВ' : 'NO'}]`;
    }
  } else if (mode === 'RECOMMENDATION') {
    delete healed.comparison;
    delete healed.tally;
  } else {
    delete healed.comparison;
    delete healed.tally;
    PERSPECTIVE_KEYS.forEach(k => { if (healed.perspectives[k]) healed.perspectives[k].vote = ''; });
  }

  return healed as OracleResponse;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "1:1" }, seed: Math.floor(Math.random() * 1000000) }
        });
        const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
        if (part?.inlineData?.data) return { image: part.inlineData.data, isFallback: false };
    } catch (e) { console.warn("Gemini Image Failed"); }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let responseData: any = null;
  let fetchedSources: OracleSource[] = [];
  let isFallback = false;
  const randomSeed = Math.floor(Math.random() * 1000000);

  const mode = getQueryMode(query);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: query }] }],
      config: { 
        systemInstruction: `You are The Oracle of Chance.
        Logic: 
        1. Current Mode: ${mode}. Query: "${query}".
        2. MANDATORY: You MUST provide content for all 8 philosophical perspectives: psychoanalysis, gestalt, russian_philosophy, german_philosophy, existential, theological, buddhist, post_modern.
        3. IF DECISION: Every philosopher MUST return a "vote" field: ("A/B" or "YES/NO"). Tally MUST sum to 8.
        4. IF RECOMMENDATION:
           - Each philosopher defines THEMES or VALUES they currently desire.
           - Final Verdict: You (The Ontological Core) synthesize these values and RECOMMEND A SPECIFIC ENTITY (title of a book, movie, meal).
        5. IF SUBJECT INQUIRY (e.g. "Yellow Brick Road"): 
           - DO NOT VOTE. Provide 8 unique deep philosophical takes. 
        6. Return Strict JSON. No silent perspectives.`,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        seed: randomSeed
      },
    });
    responseData = cleanJsonResponse(response.text || "{}");
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Evidence", uri: chunk.web.uri || "#" }));
    }
  } catch (e) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: query }] }],
        config: { 
          systemInstruction: `Oracle of Chance. Chaos: ${chaosPercentage}%. Mode: ${mode}. Return Strict JSON with all 8 perspectives. Every perspective MUST vote if DECISION.`,
          responseMimeType: "application/json",
          seed: randomSeed
        },
      });
      responseData = cleanJsonResponse(response.text || "{}");
    } catch (e2) {
      isFallback = true;
      responseData = await fallbackTextGeneration(query, language, chaosPercentage);
    }
  }

  const finalizedTextData = await healResponse(responseData || {}, query, language, chaosPercentage);

  const subStyle = (function() {
    const titleLower = (finalizedTextData.title || "").toLowerCase();
    if (finalizedTextData.category === 'MEDIA' || titleLower.includes('movie')) return chaosPercentage <= 50 ? (artStyle === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (artStyle === 'SUPREMATIST') return chaosPercentage < 40 ? 'CUBISM' : (chaosPercentage < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosPercentage < 40 ? 'IMPRESSIONISM' : (chaosPercentage < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
  })();

  const imgResult = await generateImageWithFallback(`Interpretation of "${finalizedTextData.title || "Revelation"}" in style of ${subStyle}. Dramatic composition.`);

  return { 
    ...finalizedTextData, 
    imageStyleLabel: subStyle.replace('_', '-'),
    base64Image: imgResult.image, 
    imageUrl: imgResult.url, 
    sources: fetchedSources.length > 0 ? fetchedSources : (finalizedTextData.sources || []),
    language,
    isFallback: isFallback || imgResult.isFallback
  };
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = (function() {
      const titleLower = (response.title || "").toLowerCase();
      if (response.category === 'MEDIA' || titleLower.includes('movie')) return chaosScore <= 50 ? (artStyle === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
      if (artStyle === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
      return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
    })();
    const result = await generateImageWithFallback(`Interpretation of "${response.title || "Revelation"}" in style of ${subStyle}.`);
