function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): any {
  if (!text) return {};
  try {
    let jsonPart = text.trim();
    const start = jsonPart.indexOf('{');
    const end = jsonPart.lastIndexOf('}');
    if (start === -1 || end === -1) return {};
    jsonPart = jsonPart.substring(start, end + 1);

    let sanitized = "";
    let insideString = false;
    let escaped = false;
    for (let i = 0; i < jsonPart.length; i++) {
      const char = jsonPart[i];
      if (char === '"' && !escaped) {
        insideString = !insideString;
        sanitized += char;
      } else if (insideString) {
        if (char === '\n') sanitized += "\\n";
        else if (char === '\r') sanitized += "\\r";
        else if (char === '\t') sanitized += "\\t";
        else if (char.charCodeAt(0) < 32) continue;
        else {
          sanitized += char;
          escaped = char === '\\' ? !escaped : false;
        }
      } else {
        sanitized += char;
        escaped = false;
      }
    }
    return JSON.parse(sanitized);
  } catch (e) {
    console.warn("JSON Clean failed", e);
    return {};
  }
}

async function callPollinations(prompt: string, model: string = 'openai'): Promise<string> {
  const seed = Math.floor(Math.random() * 1000000);
  const url = `https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true&model=${model}&seed=${seed}`;
  const response = await fetch(url);
  if (!response.ok) throw new Error("Pollinations Service Error");
  return await response.text();
}

function getQueryMode(query: string): 'DECISION' | 'RECOMMENDATION' | 'INQUIRY' {
  const q = query.toLowerCase().trim();
  const recMarkers = ['what should i', 'give me a', 'recommend', 'suggest', 'ideas for', 'what to', 'лучший', 'best', 'the most', 'top', 'что мне', 'посоветуй', 'рекомендуй', 'идеи для', 'выбери для меня', 'choose for me', 'best book', 'что почитать'];
  if (recMarkers.some(m => q.includes(m))) return 'RECOMMENDATION';
  const compMarkers = [' vs ', ' or ', ' или '];
  const polarMarkers = ['should i', 'can i', 'must i', 'will i', 'is it', 'do i', 'стоит ли', 'нужно ли', 'можно ли', 'будет ли', 'лучше', 'better'];
  if (compMarkers.some(m => q.includes(m)) || polarMarkers.some(m => q.includes(m)) || (q.endsWith('?') && !q.includes('what') && !q.includes('how'))) return 'DECISION';
  return 'INQUIRY';
}

async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<any> {
    const mode = getQueryMode(query);
    const isComparison = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');
    const prompt = `Act as The Oracle. Process query: "${query}". Chaos: ${chaosScore}%. 
    Return VALID JSON. No Markdown. Language: ${language === 'RU' ? 'Russian' : 'English'}.
    Perspectives: psychoanalysis, gestalt, russian_philosophy, german_philosophy, existential, theological, buddhist, post_modern.
    Every perspective MUST VOTE if Mode is DECISION. Be unique.`;
    try {
      const raw = await callPollinations(prompt, 'openai');
      return cleanJsonResponse(raw);
    } catch (e) {
      const raw = await callPollinations(prompt, 'mistral');
      return cleanJsonResponse(raw);
    }
}

async function healResponse(data: any, query: string, language: 'EN' | 'RU', chaosScore: number): Promise<OracleResponse> {
  const mode = getQueryMode(query);
  const isDecision = mode !== 'INQUIRY';
  const isComparisonQuery = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');

  const healed: any = {
    ...data,
    type: data.type || (mode === 'RECOMMENDATION' ? 'RECOMMENDATION' : (isComparisonQuery ? 'COMPARISON' : 'SINGLE')),
    isDecision,
    title: data.title || query.substring(0, 40) + "...",
    verdict: data.verdict || "",
    detailedAnalysis: data.detailedAnalysis || "",
    category: data.category || "LIFE",
    perspectives: data.perspectives || {},
    sources: data.sources && Array.isArray(data.sources) && data.sources.length > 0 ? data.sources : [
      { title: "Universal Knowledge", uri: `https://en.wikipedia.org/wiki/Special:Search?search=${encodeURIComponent(query)}` },
      { title: "Deep Inquiry", uri: `https://plato.stanford.edu/search/searcher.py?query=${encodeURIComponent(query)}` }
    ]
  };

  // Ensure all 8 perspectives are populated and HAVE UNIQUE ANALYSES
  PERSPECTIVE_KEYS.forEach(k => {
    if (!healed.perspectives[k]) healed.perspectives[k] = {};
    const p = healed.perspectives[k];

    // Force vote if missing in Decision Mode
    if (mode === 'DECISION' && (!p.vote || p.vote === '')) {
      p.vote = Math.random() > (chaosScore / 100) ? (isComparisonQuery ? 'A' : 'YES') : (isComparisonQuery ? 'B' : 'NO');
    }

    // Replace generic filler with specific insights
    const isFiller = !p.analysis || p.analysis.length < 100 || p.analysis.toLowerCase().includes("deep alignment") || p.analysis.toLowerCase().includes("acknowledging the underlying");

    if (isFiller) {
      const names: any = {
        psychoanalysis: language === 'EN' ? "The Freudian Lens" : "Психоанализ",
        gestalt: language === 'EN' ? "The Gestalt Perspective" : "Гештальт-подход",
        russian_philosophy: language === 'EN' ? "The Russian Heart" : "Русская Идея",
        german_philosophy: language === 'EN' ? "The Kantian Categorical" : "Германский Идеализм",
        existential: language === 'EN' ? "The Existential Void" : "Экзистенциальный выбор",
        theological: language === 'EN' ? "The Sacred Dimension" : "Теологический взгляд",
        buddhist: language === 'EN' ? "The Zen Void" : "Дзен-буддизм",
        post_modern: language === 'EN' ? "The Hyper-Real Deconstruction" : "Постмодернизм"
      };

      const specificInsight = language === 'EN' 
        ? `From the ${names[k]} viewpoint, your question about "${query}" isn't merely a point of data. It represents a fundamental tension between your perceived reality and the latent structures of the subconscious world. We must deconstruct the impulse that brought you to this choice, acknowledging that the resolution lies in the unique synthesis of your current history and the random noise of the universe.`
        : `С точки зрения ${names[k]}, ваш вопрос о «${query}» — это не просто выбор. Это фундаментальное напряжение между вашей реальностью и скрытыми структурами подсознательного. Мы должны деконструировать импульс, который привел вас сюда, признавая, что решение лежит в уникальном синтезе вашей личной истории и случайного шума вселенной.`;

      p.verdict = p.verdict || (mode === 'RECOMMENDATION' ? "SYNERGY" : "SYNTHESIS");
      p.analysis = specificInsight;
    }
  });

  // Synthesize missing Ontological Core if Gemini failed
  const isVerdictEmpty = !healed.detailedAnalysis || healed.detailedAnalysis.length < 100;
  if (isVerdictEmpty) {
    const perspectivesSummary = Object.values(healed.perspectives).map((p: any) => p.analysis.substring(0, 100)).join("... ");
    healed.detailedAnalysis = language === 'EN'
      ? `The Oracle has synthesized the collective voices of the Council. Regarding "${query}", we find a confluence of trajectories that point toward a decisive moment. The logic of the void suggests that this inquiry is a catalyst for transformation. Our analysis, drawing from the insights below, indicates that ${healed.verdict || 'the path is clearing'}. \n\nSUMMARY OF VOICES: ${perspectivesSummary}...`
      : `Оракул синтезировал коллективные голоса Совета. Относительно «${query}» мы видим слияние траекторий, указывающих на решающий момент. Логика пустоты предполагает, что этот запрос является катализатором трансформации. Наш анализ, опирающийся на приведенные ниже идеи, указывает на то, что ${healed.verdict || 'путь проясняется'}. \n\nИТОГ ГОЛОСОВ: ${perspectivesSummary}...`;
  }

  if (mode === 'DECISION') {
    let votesA = 0; let votesB = 0; let votesYes = 0; let votesNo = 0;
    Object.values(healed.perspectives).forEach((p: any) => {
      const v = String(p.vote || "").toUpperCase().trim();
      if (v === 'A' || v === 'OPTION A' || v.startsWith('A')) votesA++;
      else if (v === 'B' || v === 'OPTION B' || v.startsWith('B')) votesB++;
      else if (v === 'YES' || v === 'FOR' || v === 'TRUE' || v.startsWith('Y') || v.startsWith('ДА')) votesYes++;
      else if (v === 'NO' || v === 'AGAINST' || v === 'FALSE' || v.startsWith('N') || v.startsWith('НЕ')) votesNo++;
    });

    if (votesA + votesB + votesYes + votesNo === 0) {
      votesYes = Math.round(8 * (1 - (chaosScore / 100)));
      votesNo = 8 - votesYes;
    }

    if (healed.type === 'COMPARISON') {
      const total = votesA + votesB || 8;
      const scoreA = Math.round((votesA / total) * 100);
      const scoreB = 100 - scoreA;
      const parts = query.split(/ vs | or | или /i);
      healed.comparison = {
        optionA: { title: data.comparison?.optionA?.title || parts[0]?.trim() || "Path A", description: data.comparison?.optionA?.description || "Primary trajectory.", score: scoreA },
        optionB: { title: data.comparison?.optionB?.title || parts[1]?.trim() || "Path B", description: data.comparison?.optionB?.description || "Secondary trajectory.", score: scoreB },
        winner: votesA > votesB ? 'A' : (votesB > votesA ? 'B' : 'DRAW'),
        tally: `${votesA} vs ${votesB}`
      };
      if (!healed.verdict) {
        healed.verdict = votesA > votesB ? `CHOOSE ${healed.comparison.optionA.title.toUpperCase()}` : (votesB > votesA ? `CHOOSE ${healed.comparison.optionB.title.toUpperCase()}` : "STAY IN NEUTRALITY");
      }
    } else {
      healed.tally = `${votesYes} vs ${votesNo}`;
      const baseVerdict = (healed.verdict || (votesYes >= votesNo ? "AFFIRMATIVE" : "NEGATIVE")).replace(/\[.*\]/, '').trim();
      healed.verdict = `${baseVerdict} [${votesYes} ${language === 'RU' ? 'ЗА' : 'YES'} / ${votesNo} ${language === 'RU' ? 'ПРОТИВ' : 'NO'}]`;
    }
  }

  return healed as OracleResponse;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "1:1" }, seed: Math.floor(Math.random() * 1000000) }
        });
        const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
        if (part?.inlineData?.data) return { image: part.inlineData.data, isFallback: false };
    } catch (e) { console.warn("Gemini Image Failed"); }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

