      p.vote = isComparisonQuery ? (isAorYes ? 'A' : 'B') : (isAorYes ? 'YES' : 'NO');
    }

    // Replace generic filler with specific insights
    const isFiller = !p.analysis || p.analysis.length < 120 || p.analysis.toLowerCase().includes("deep alignment") || p.analysis.toLowerCase().includes("acknowledging the underlying");

    if (isFiller) {
      const names: any = {
        psychoanalysis: language === 'EN' ? "The Lacanian Mirror" : "Лакановское зеркало",
        gestalt: language === 'EN' ? "The Field Theory" : "Теория поля",
