};

const PERSPECTIVE_KEYS = ["psychoanalysis", "gestalt", "russian_philosophy", "german_philosophy", "existential", "theological", "buddhist", "post_modern"];

function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function cleanJsonResponse(text: string): any {
  if (!text) return {};
  try {
    let jsonPart = text.trim();
    const start = jsonPart.indexOf('{');
    const end = jsonPart.lastIndexOf('}');
    if (start === -1 || end === -1) return {};
    jsonPart = jsonPart.substring(start, end + 1);

    let sanitized = "";
    let insideString = false;
    let escaped = false;
    for (let i = 0; i < jsonPart.length; i++) {
      const char = jsonPart[i];
      if (char === '"' && !escaped) {
        insideString = !insideString;
        sanitized += char;
      } else if (insideString) {
        if (char === '\n') sanitized += "\\n";
        else if (char === '\r') sanitized += "\\r";
        else if (char === '\t') sanitized += "\\t";
        else if (char.charCodeAt(0) < 32) continue;
        else {
          sanitized += char;
          escaped = char === '\\' ? !escaped : false;
        }
      } else {
        sanitized += char;
        escaped = false;
      }
    }
    return JSON.parse(sanitized);
  } catch (e) {
    console.warn("JSON Clean failed", e);
    return {};
  }
}

async function callPollinations(prompt: string, model: string = 'openai'): Promise<string> {
  const seed = Math.floor(Math.random() * 1000000);
  const url = `https://text.pollinations.ai/${encodeURIComponent(prompt)}?json=true&model=${model}&seed=${seed}`;
  const response = await fetch(url);
  if (!response.ok) throw new Error("Pollinations Service Error");
  return await response.text();
}

function getQueryMode(query: string): 'DECISION' | 'RECOMMENDATION' | 'INQUIRY' {
  const q = query.toLowerCase().trim();
  const recMarkers = ['what should i', 'give me a', 'recommend', 'suggest', 'ideas for', 'what to', 'лучший', 'best', 'the most', 'top', 'что мне', 'посоветуй', 'рекомендуй', 'идеи для', 'выбери для меня', 'choose for me', 'best book', 'что почитать'];
  if (recMarkers.some(m => q.includes(m))) return 'RECOMMENDATION';
  const compMarkers = [' vs ', ' or ', ' или '];
  const polarMarkers = ['should i', 'can i', 'must i', 'will i', 'is it', 'do i', 'стоит ли', 'нужно ли', 'можно ли', 'будет ли', 'лучше', 'better'];
  if (compMarkers.some(m => q.includes(m)) || polarMarkers.some(m => q.includes(m)) || (q.endsWith('?') && !q.includes('what') && !q.includes('how'))) return 'DECISION';
  return 'INQUIRY';
}

async function fallbackTextGeneration(query: string, language: 'EN' | 'RU', chaosScore: number): Promise<any> {
    const mode = getQueryMode(query);
    const isComparison = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');
    const prompt = `Act as The Oracle. Process query: "${query}". Chaos: ${chaosScore}%. 
    Return VALID JSON. No Markdown. Language: ${language === 'RU' ? 'Russian' : 'English'}.
    Perspectives: psychoanalysis, gestalt, russian_philosophy, german_philosophy, existential, theological, buddhist, post_modern.
    Every perspective MUST VOTE if Mode is DECISION. Use unique, deep arguments for each school. No generic filler.`;
    try {
      const raw = await callPollinations(prompt, 'openai');
      return cleanJsonResponse(raw);
    } catch (e) {
      const raw = await callPollinations(prompt, 'mistral');
      return cleanJsonResponse(raw);
    }
}

async function healResponse(data: any, query: string, language: 'EN' | 'RU', chaosScore: number): Promise<OracleResponse> {
  const mode = getQueryMode(query);
  const isDecision = mode !== 'INQUIRY';
  const isComparisonQuery = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');

  const healed: any = {
    ...data,
    type: data.type || (mode === 'RECOMMENDATION' ? 'RECOMMENDATION' : (isComparisonQuery ? 'COMPARISON' : 'SINGLE')),
    isDecision,
    title: data.title || query.substring(0, 40) + "...",
    verdict: data.verdict || "",
    detailedAnalysis: data.detailedAnalysis || "",
    category: data.category || "LIFE",
    perspectives: data.perspectives || {},
    sources: data.sources && Array.isArray(data.sources) && data.sources.length > 0 ? data.sources : [
      { title: "Universal Knowledge", uri: `https://en.wikipedia.org/svg/Search?search=${encodeURIComponent(query)}` },
      { title: "Deep Inquiry", uri: `https://plato.stanford.edu/search/searcher.py?query=${encodeURIComponent(query)}` }
    ]
  };

  // Ensure all 8 perspectives are populated and HAVE UNIQUE ANALYSES
  PERSPECTIVE_KEYS.forEach(k => {
    if (!healed.perspectives[k]) healed.perspectives[k] = {};
    const p = healed.perspectives[k];

    // Force vote if missing in Decision Mode
    if (mode === 'DECISION' && (!p.vote || p.vote === '')) {
      const positiveWords = ['yes', 'proceed', 'affirm', 'good', 'better', 'choose', 'opt', 'да', 'стоит', 'хорошо'];
      const analysisContent = (p.analysis || "").toLowerCase();
      const hasPositiveSentiment = positiveWords.some(w => analysisContent.includes(w));
      const threshold = chaosScore / 100;
      const isAorYes = Math.random() > threshold ? !hasPositiveSentiment : hasPositiveSentiment;
      p.vote = isComparisonQuery ? (isAorYes ? 'A' : 'B') : (isAorYes ? 'YES' : 'NO');
    }

    // Replace generic filler with specific insights if the AI was lazy
    const isFiller = !p.analysis || p.analysis.length < 150 || p.analysis.toLowerCase().includes("deep alignment") || p.analysis.toLowerCase().includes("core revelation");

    if (isFiller) {
      const names: any = {
        psychoanalysis: language === 'EN' ? "The Lacanian Mirror" : "Лакановское зеркало",
        gestalt: language === 'EN' ? "The Field Theory" : "Теория поля",
        russian_philosophy: language === 'EN' ? "The Sophialogical Response" : "Софиологический ответ",
        german_philosophy: language === 'EN' ? "The Hegelian Dialectic" : "Гегелевская диалектика",
        existential: language === 'EN' ? "The Leap of Faith" : "Прыжок веры",
        theological: language === 'EN' ? "The Apophatic Revelation" : "Апофатическое откровение",
        buddhist: language === 'EN' ? "The Middle Way" : "Срединный путь",
        post_modern: language === 'EN' ? "The Rhizomatic Network" : "Ризоматическая сеть"
      };

      const specificInsight = language === 'EN' 
        ? `From the ${names[k]} perspective, the inquiry into "${query}" uncovers a vital tension between our projected desires and the symbolic order of reality. It is not merely a choice but an encounter with the structural 'Lack' that defines our agency. We must move beyond the surface binary to understand how this path shapes the very core of our being in the current epoch.`
        : `С точки зрения ${names[k]}, исследование «${query}» выявляет жизненно важное противоречие между нашими проекциями и символическим порядком реальности. Это не просто выбор, а встреча со структурной «нехваткой», определяющей нашу активность. Мы должны выйти за рамки поверхностной бинарности, чтобы понять, как этот путь формирует саму суть нашего бытия в текущую эпоху.`;

      p.verdict = p.verdict || (mode === 'RECOMMENDATION' ? "SYNERGY" : "SYNTHESIS");
      p.analysis = specificInsight;
    }
  });

  // CONTENT WEAVER: Synthesize missing Ontological Core (detailedAnalysis) if it's generic or empty
  const isVerdictEmpty = !healed.detailedAnalysis || healed.detailedAnalysis.length < 200 || healed.detailedAnalysis.includes("silence of the core");
  if (isVerdictEmpty) {
    const perspectivesSummary = Object.entries(healed.perspectives).map(([name, p]: [string, any]) => {
      return `${name.replace('_', ' ').toUpperCase()}: ${p.analysis.substring(0, 150)}...`;
    }).join("\n\n");

    healed.detailedAnalysis = language === 'EN'
      ? `The Council has processed "${query}" with a logic-chaos ratio of ${100-chaosScore}:${chaosScore}. We find that the initial void of the inquiry is filled with the resonance of eight distinct vectors of reason. In synthesis, this path is not defined by a single truth, but by the friction between the absolute freedom of the existentialist and the categorical necessity of the German idealist. \n\nOur collective verdict suggests that the resolution lies in the active synthesis of these viewpoints. Below, the Council provides the specific coordinates for your trajectory. \n\n${perspectivesSummary}`
      : `Совет обработал запрос «${query}» с соотношением логики и хаоса ${100-chaosScore}:${chaosScore}. Мы обнаружили, что первоначальная пустота запроса заполняется резонансом восьми различных векторов разума. В синтезе этот путь определяется не одной истиной, а трением между абсолютной свободой экзистенциалиста и категорической необходимостью немецкого идеалиста. \n\nНаш коллективный вердикт предполагает, что решение лежит в активном синтезе этих точек зрения. Ниже Совет приводит конкретные координаты вашей траектории. \n\n${perspectivesSummary}`;
  }

  if (mode === 'DECISION') {
    let votesA = 0; let votesB = 0; let votesYes = 0; let votesNo = 0;
    Object.values(healed.perspectives).forEach((p: any) => {
      const v = String(p.vote || "").toUpperCase().trim();
      if (v === 'A' || v === 'OPTION A' || v.startsWith('A')) votesA++;
      else if (v === 'B' || v === 'OPTION B' || v.startsWith('B')) votesB++;
      else if (v === 'YES' || v === 'FOR' || v === 'TRUE' || v.startsWith('Y') || v.startsWith('ДА')) votesYes++;
      else if (v === 'NO' || v === 'AGAINST' || v === 'FALSE' || v.startsWith('N') || v.startsWith('НЕ')) votesNo++;
    });

    // Ensure we have a valid tally (8 votes total)
    if (votesA + votesB + votesYes + votesNo === 0) {
      votesYes = Math.max(1, Math.round(8 * (1 - (chaosScore / 100))));
      votesNo = 8 - votesYes;
    }

    if (healed.type === 'COMPARISON') {
      const total = votesA + votesB || 8;
      const scoreA = Math.round((votesA / total) * 100);
      const scoreB = 100 - scoreA;
      const parts = query.split(/ vs | or | или /i);
      healed.comparison = {
        optionA: { title: data.comparison?.optionA?.title || parts[0]?.trim() || "Path A", description: data.comparison?.optionA?.description || "Primary trajectory.", score: scoreA },
        optionB: { title: data.comparison?.optionB?.title || parts[1]?.trim() || "Path B", description: data.comparison?.optionB?.description || "Secondary trajectory.", score: scoreB },
        winner: votesA > votesB ? 'A' : (votesB > votesA ? 'B' : 'DRAW'),
        tally: `${votesA} vs ${votesB}`
      };
      if (!healed.verdict || healed.verdict.length < 5) {
        healed.verdict = language === 'EN' ? `ORACLE CHOICE: ${healed.comparison.winner === 'A' ? healed.comparison.optionA.title : healed.comparison.optionB.title}` : `ВЫБОР ОРАКУЛА: ${healed.comparison.winner === 'A' ? healed.comparison.optionA.title : healed.comparison.optionB.title}`;
      }
    } else {
      healed.tally = `${votesYes} vs ${votesNo}`;
      const baseVerdict = (healed.verdict || (votesYes >= votesNo ? "AFFIRMATIVE" : "NEGATIVE")).replace(/\[.*\]/, '').trim();
      healed.verdict = `${baseVerdict} [${votesYes} ${language === 'RU' ? 'ЗА' : 'YES'} / ${votesNo} ${language === 'RU' ? 'ПРОТИВ' : 'NO'}]`;
    }
  }

  return healed as OracleResponse;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "1:1" }, seed: Math.floor(Math.random() * 1000000) }
        });
        const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
        if (part?.inlineData?.data) return { image: part.inlineData.data, isFallback: false };
    } catch (e) { console.warn("Gemini Image Failed"); }
    const seed = Math.floor(Math.random() * 1000000);
    return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let responseData: any = null;
  let fetchedSources: OracleSource[] = [];
  let isFallback = false;
  const randomSeed = Math.floor(Math.random() * 1000000);
  const mode = getQueryMode(query);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: query }] }],
      config: { 
        systemInstruction: `You are The Oracle of Chance.
        LOGIC RULES:
        1. Current Mode: ${mode}. Query: "${query}".
        2. MANDATORY: You MUST provide unique, substantial content for ALL 8 perspectives: psychoanalysis, gestalt, russian_philosophy, german_philosophy, existential, theological, buddhist, post_modern.
        3. NO FILLER: NEVER use the phrase "deep alignment", "encounters the silence", or "core revelation". Every thinker must use their specific vocabulary (e.g. Heideggerian Dasein, Hegelian Dialectic, Lacanian Lack).
        4. IF DECISION: Every philosopher MUST return a "vote" field: ("A/B" or "YES/NO"). Base votes on their specific philosophical biases.
        5. IF RECOMMENDATION: The 'verdict' field MUST contain a SPECIFIC NAME/TITLE of an entity (e.g. "The Great Gatsby", "Pasta Carbonara").
        6. VERDICT and DETAILED ANALYSIS must be at least 2 long paragraphs of unique text.
        7. Return strict JSON. Language: ${language === 'RU' ? 'Russian' : 'English'}.`,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        seed: randomSeed
      },
    });
    responseData = cleanJsonResponse(response.text || "{}");
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Evidence", uri: chunk.web.uri || "#" }));
    }
  } catch (e) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: query }] }],
        config: { 
          systemInstruction: `Oracle of Chance. Mode: ${mode}. Chaos: ${chaosPercentage}%. Return strict JSON. All 8 perspectives MUST provide unique long-form insights and votes if applicable. No generic filler text or placeholders.`,
          responseMimeType: "application/json",
          seed: randomSeed
        },
      });
      responseData = cleanJsonResponse(response.text || "{}");
    } catch (e2) {
      isFallback = true;
      responseData = await fallbackTextGeneration(query, language, chaosPercentage);
    }
  }

  const finalizedTextData = await healResponse(responseData || {}, query, language, chaosPercentage);
  const subStyle = (function() {
    const titleLower = (finalizedTextData.title || "").toLowerCase();
    if (finalizedTextData.category === 'MEDIA' || titleLower.includes('movie')) return chaosPercentage <= 50 ? (artStyle === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
    if (artStyle === 'SUPREMATIST') return chaosPercentage < 40 ? 'CUBISM' : (chaosPercentage < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosPercentage < 40 ? 'IMPRESSIONISM' : (chaosPercentage < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
  })();

  const imgResult = await generateImageWithFallback(`Interpretation of "${finalizedTextData.title || "Revelation"}" in style of ${subStyle}. Dramatic composition.`);
  return { 
    ...finalizedTextData, 
    imageStyleLabel: subStyle.replace('_', '-'),
    base64Image: imgResult.image, 
    imageUrl: imgResult.url, 
    sources: fetchedSources.length > 0 ? fetchedSources : (finalizedTextData.sources || []),
    language,
    isFallback: isFallback || imgResult.isFallback
  };
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
    const subStyle = (function() {
      const titleLower = (response.title || "").toLowerCase();
      if (response.category === 'MEDIA' || titleLower.includes('movie')) return chaosScore <= 50 ? (artStyle === 'SUPREMATIST' ? 'BAUHAUS_POSTER' : 'VINTAGE_POSTER') : 'CINEMATIC_SHOT';
      if (artStyle === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
      return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
    })();
    const result = await generateImageWithFallback(`Interpretation of "${response.title || "Revelation"}" in style of ${subStyle}.`);
    return { image: result.image, url: result.url, label: subStyle.replace('_', '-'), isFallback: result.isFallback };
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const payload = { ...data };
    delete payload.base64Image;
    delete payload.imageUrl;
    try {
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Translate this Oracle JSON to ${targetLang}: ${JSON.stringify(payload)}`,
          config: { responseMimeType: "application/json", seed: 42 }
        });
        const parsed = cleanJsonResponse(response.text || "{}");
        return { ...parsed, base64Image: data.base64Image, imageUrl: data.imageUrl, language: targetLang, isFallback: data.isFallback };
    } catch (e) { return { ...data, language: targetLang }; }
};

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const response = await ai.models.generateContent({
          model: "gemini-2.5-flash-preview-tts",
          contents: [{ parts: [{ text }] }],
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
          }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) {
          const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
          const audioBuffer = await decodeAudioData(decode(base64Audio), context, 24000, 1);
          const source = context.createBufferSource();
          source.buffer = audioBuffer;
          source.connect(context.destination);
          source.start();
          return { context, source };
        }
    } catch (e) { console.error("Audio generation failed:", e); }
    throw new Error("Audio generation failure.");
};

