      : `Совет Восьми синтезировал «Новую Истину» относительно «${query}». В то время как первоначальная поверхностная логика мира может предлагать простую бинарность, наш глубокий онтологический аудит выявляет сложное пересечение метафизических течений. Это не просто решение; это проявление навигации духа в гиперреальном ландшафте XXI века. \n\nСинтез наших восьми голосов предполагает, что окончательное решение находится не в отбрасывании одной стороны, а в радикальном принятии напряжения между ними. Этот «Третий путь» возникает из трения разума и хаоса, логики и духа. \n\n### Коллективный резонанс:\n\n${perspectivesSummary}`;
  }

  if (mode === 'DECISION') {
    let votesA = 0; let votesB = 0; let votesYes = 0; let votesNo = 0;
    Object.values(healed.perspectives).forEach((p: any) => {
      const v = String(p.vote || "").toUpperCase().trim();
      if (v === 'A' || v === 'OPTION A' || v.startsWith('A')) votesA++;
      else if (v === 'B' || v === 'OPTION B' || v.startsWith('B')) votesB++;
      else if (v === 'YES' || v === 'FOR' || v === 'TRUE' || v.startsWith('Y') || v.startsWith('ДА')) votesYes++;
      else if (v === 'NO' || v === 'AGAINST' || v === 'FALSE' || v.startsWith('N') || v.startsWith('НЕ')) votesNo++;
    });

    if (votesA + votesB + votesYes + votesNo === 0) {
      votesYes = Math.max(1, Math.round(8 * (1 - (chaosScore / 100))));
      votesNo = 8 - votesYes;
    }

    if (healed.type === 'COMPARISON') {
      const total = votesA + votesB || 8;
      const scoreA = Math.round((votesA / total) * 100);
      const scoreB = 100 - scoreA;
      const parts = query.split(/ vs | or | или /i);
      healed.comparison = {
        optionA: { title: data.comparison?.optionA?.title || parts[0]?.trim() || "Path A", description: data.comparison?.optionA?.description || "The primary trajectory of reason.", score: scoreA },
        optionB: { title: data.comparison?.optionB?.title || parts[1]?.trim() || "Path B", description: data.comparison?.optionB?.description || "The secondary vector of possibility.", score: scoreB },
        winner: votesA > votesB ? 'A' : (votesB > votesA ? 'B' : 'DRAW'),
        tally: `${votesA} vs ${votesB}`
      };
      const winnerName = votesA > votesB ? healed.comparison.optionA.title : (votesB > votesA ? healed.comparison.optionB.title : "The Void");
      healed.verdict = language === 'EN' ? `ORACLE'S CHOICE: ${winnerName.toUpperCase()}` : `ВЫБОР ОРАКУЛА: ${winnerName.toUpperCase()}`;
    } else {
      healed.tally = `${votesYes} vs ${votesNo}`;
      const baseVerdict = (healed.verdict || (votesYes >= votesNo ? "AFFIRMATIVE" : "NEGATIVE")).replace(/\[.*\]/, '').trim();
      healed.verdict = `${baseVerdict} [${votesYes} ${language === 'RU' ? 'ЗА' : 'YES'} / ${votesNo} ${language === 'RU' ? 'ПРОТИВ' : 'NO'}]`;
    }
  }

  return healed as OracleResponse;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "1:1" }, seed: Math.floor(Math.random() * 1000000) }
    });
    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData?.data) return { image: part.inlineData.data, isFallback: false };
  } catch (e) { console.warn("Gemini Image Failed"); }
  const seed = Math.floor(Math.random() * 1000000);
  return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

