      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: query }] }],
        config: { 
          systemInstruction: `Oracle Council of Eight. Mode: ${mode}. Chaos: ${chaosPercentage}%. Return strict JSON. All 8 perspectives MUST provide unique long-form jargon-rich insights and votes. NO GENERIC PLACEHOLDERS. Minimum 300 words for the Core synthesis.`,
          responseMimeType: "application/json",
          seed: randomSeed
        },
      });
      responseData = cleanJsonResponse(response.text || "{}");
    } catch (e2) {
