}

function getQueryMode(query: string): 'DECISION' | 'RECOMMENDATION' | 'INQUIRY' {
  const q = query.toLowerCase().trim();
  const recMarkers = ['what should i', 'give me a', 'recommend', 'suggest', 'ideas for', 'what to', 'лучший', 'best', 'the most', 'top', 'что мне', 'посоветуй', 'рекомендуй', 'идеи для', 'выбери для меня', 'choose for me', 'best book', 'что почитать', 'watch', 'посмотреть', 'movie', 'film'];
  if (recMarkers.some(m => q.includes(m))) return 'RECOMMENDATION';
  const compMarkers = [' vs ', ' or ', ' или '];
  const polarMarkers = ['should i', 'can i', 'must i', 'will i', 'is it', 'do i', 'стоит ли', 'нужно ли', 'можно ли', 'будет ли', 'лучше', 'better'];
  if (compMarkers.some(m => q.includes(m)) || polarMarkers.some(m => q.includes(m)) || (q.endsWith('?') && !q.includes('what') && !q.includes('how'))) return 'DECISION';
  return 'INQUIRY';
}

async function healResponse(data: any, query: string, language: 'EN' | 'RU', chaosScore: number): Promise<OracleResponse> {
  const mode = getQueryMode(query);
  const isDecision = mode !== 'INQUIRY';
  const isComparisonQuery = query.toLowerCase().includes(' vs ') || query.toLowerCase().includes(' or ') || query.toLowerCase().includes(' или ');

  const healed: any = {
    ...data,
    type: data.type || (mode === 'RECOMMENDATION' ? 'RECOMMENDATION' : (isComparisonQuery ? 'COMPARISON' : 'SINGLE')),
    isDecision,
    title: data.title || query.substring(0, 40) + "...",
    verdict: data.verdict || "",
    detailedAnalysis: data.detailedAnalysis || "",
    category: data.category || "LIFE",
    perspectives: data.perspectives || {},
    sources: data.sources && Array.isArray(data.sources) && data.sources.length > 0 ? data.sources : [
      { title: "Universal Knowledge", uri: `https://en.wikipedia.org/wiki/Special:Search?search=${encodeURIComponent(query)}` },
      { title: "Deep Inquiry", uri: `https://plato.stanford.edu/search/searcher.py?query=${encodeURIComponent(query)}` }
    ]
  };

  // Verdict healing
  if (!healed.verdict || healed.verdict.length < 5) {
     healed.verdict = language === 'EN' ? "ONTOLOGICAL REVELATION" : "ОНТОЛОГИЧЕСКОЕ ОТКРОВЕНИЕ";
  }

  // Perspectives healing - if any are lazy or missing, generate them dynamically
  for (const k of PERSPECTIVE_KEYS) {
    if (!healed.perspectives[k]) healed.perspectives[k] = {};
    const p = healed.perspectives[k];

    const isLazy = !p.analysis || p.analysis.length < 200 || p.analysis.toLowerCase().includes("condemned to be free");
    if (isLazy) {
      p.analysis = await generateDynamicPerspective(k.replace('_', ' '), query, language, chaosScore);
      p.verdict = p.verdict || "VOICE OF TRUTH";
    }

    // Vote logic
    if (mode === 'DECISION' && (!p.vote || p.vote === '')) {
      const posWords = ['yes', 'affirm', 'proceed', 'choose', 'opt', 'да', 'стоит', 'хорошо', 'a'];
      const negWords = ['no', 'negate', 'reject', 'avoid', 'нет', 'не стоит', 'плохо', 'b'];
      const analysisLower = (p.analysis || "").toLowerCase();
      const posCount = posWords.filter(w => analysisLower.includes(w)).length;
      const negCount = negWords.filter(w => analysisLower.includes(w)).length;
      const threshold = chaosScore / 100;
      const isPositive = Math.random() > threshold ? posCount >= negCount : posCount < negCount;
      p.vote = isComparisonQuery ? (isPositive ? 'A' : 'B') : (isPositive ? 'YES' : 'NO');
    }
  }

  // Core Analysis synthesis - frames as a compromise summary of all voices
  const isCoreSparse = !healed.detailedAnalysis || healed.detailedAnalysis.length < 400;
  if (isCoreSparse) {
    const perspectivesSummary = Object.entries(healed.perspectives).map(([name, p]: [string, any]) => {
      const title = name.replace('_', ' ').toUpperCase();
      return `**${title}**: ${p.analysis}`;
    }).join("\n\n");

    healed.detailedAnalysis = language === 'EN'
      ? `The Council of Eight has convened to synthesize a unified Ontological Core regarding "${query}". Our synthesis acts as a precarious compromise between eight radical worldviews, modulated by your current Chaos calibration (${chaosScore}%). 

While the Psychoanalyst finds lack and the Buddhist finds emptiness, the German Idealist seeks a structural synthesis. We have woven these disparate threads into a single tapestry of meaning. We conclude that "${query}" is not merely a choice or a query, but a pivotal moment of self-definition in a hyperreal landscape.

### The Collective Resonance:

${perspectivesSummary}`
      : `Совет Восьми собрался, чтобы синтезировать единое Онтологическое Ядро относительно «${query}». Наш синтез выступает как зыбкий компромисс между восемью радикальными мировоззрениями, модулированный вашей текущей калибровкой Хаоса (${chaosScore}%).

### Коллективный резонанс:

${perspectivesSummary}`;
  }

  // Vote Tally
  if (mode === 'DECISION') {
    let votesA = 0; let votesB = 0; let votesYes = 0; let votesNo = 0;
    Object.values(healed.perspectives).forEach((p: any) => {
      const v = String(p.vote || "").toUpperCase().trim();
      if (v === 'A' || v.startsWith('A')) votesA++;
      else if (v === 'B' || v.startsWith('B')) votesB++;
      else if (v === 'YES' || v.startsWith('Y') || v.startsWith('ДА')) votesYes++;
      else if (v === 'NO' || v.startsWith('N') || v.startsWith('НЕ')) votesNo++;
    });

    if (healed.type === 'COMPARISON') {
      const parts = query.split(/ vs | or | или /i);
      healed.comparison = {
        optionA: { title: data.comparison?.optionA?.title || parts[0]?.trim() || "Option A", description: data.comparison?.optionA?.description || "The primary vector of desire.", score: Math.round((votesA / 8) * 100) },
        optionB: { title: data.comparison?.optionB?.title || parts[1]?.trim() || "Option B", description: data.comparison?.optionB?.description || "The secondary vector of possibility.", score: Math.round((votesB / 8) * 100) },
        winner: votesA > votesB ? 'A' : (votesB > votesA ? 'B' : 'DRAW'),
        tally: `${votesA} vs ${votesB}`
      };
      const winnerName = votesA > votesB ? healed.comparison.optionA.title : (votesB > votesA ? healed.comparison.optionB.title : "THE VOID");
      healed.verdict = language === 'EN' ? `ORACLE'S CHOICE: ${winnerName.toUpperCase()}` : `ВЫБОР ОРАКУЛА: ${winnerName.toUpperCase()}`;
    } else {
      healed.tally = `${votesYes} vs ${votesNo}`;
      const baseVerdict = (healed.verdict || (votesYes >= votesNo ? "AFFIRMATIVE" : "NEGATIVE")).replace(/\[.*\]/, '').trim();
      healed.verdict = `${baseVerdict} [${votesYes} ${language === 'RU' ? 'ЗА' : 'YES'} / ${votesNo} ${language === 'RU' ? 'ПРОТИВ' : 'NO'}]`;
    }
  }

  return healed as OracleResponse;
}

async function generateImageWithFallback(prompt: string): Promise<{ image?: string; url?: string; isFallback?: boolean }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "1:1" }, seed: Math.floor(Math.random() * 1000000) }
    });
    const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (part?.inlineData?.data) return { image: part.inlineData.data, isFallback: false };
  } catch (e) { console.warn("Gemini Image Failed"); }
  const seed = Math.floor(Math.random() * 1000000);
  return { url: `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&nologo=true&seed=${seed}`, isFallback: true };
}

export const consultOracle = async (query: string, chaosPercentage: number, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST' = 'SUPREMATIST', language: 'EN' | 'RU' = 'EN'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let responseData: any = null;
  let fetchedSources: OracleSource[] = [];
  const randomSeed = Math.floor(Math.random() * 1000000);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: `A seeker asks the Council: "${query}". Chaos: ${chaosPercentage}%.` }] }],
      config: { 
        systemInstruction: `You are the Universal Oracle. You must interview 8 distinct Philosophers about the seeker's query:
        1. Psychoanalysis (Lacanian)
        2. Gestalt (Längle/Perls)
        3. Russian Philosophy (Berdyaev/Solovyov)
        4. German Philosophy (Hegel/Kant)
        5. Existentialism (Sartre/Heidegger)
        6. Theology (Aquinas/Augustine)
        7. Zen Buddhism (Dōgen)
        8. Post-Modernism (Baudrillard/Derrida)

        MANDATORY RULES:
        - For each philosopher, provide a UNIQUE, deep response (min 250 words) that directly addresses the specific nouns/verbs in the query: "${query}".
        - NEVER use standard AI templates like "you are condemned to be free". Inhabit the persona.
        - The "detailedAnalysis" must be an Ontological Core synthesis—a compromising summary of all 8 voices.
        - Return VALID JSON ONLY. Language: ${language === 'RU' ? 'Russian' : 'English'}.`,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        seed: randomSeed
      },
    });
    responseData = cleanJsonResponse(response.text || "{}");
    const candidate = response.candidates?.[0];
    if (candidate?.groundingMetadata?.groundingChunks) {
      fetchedSources = candidate.groundingMetadata.groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({ title: chunk.web.title || "Evidence", uri: chunk.web.uri || "#" }));
    }
  } catch (e) {
    // Fallback to high-reliability fallback text generation
    responseData = await healResponse({}, query, language, chaosPercentage);
  }

  const finalizedTextData = await healResponse(responseData || {}, query, language, chaosPercentage);

  const subStyle = (function() {
    if (artStyle === 'SUPREMATIST') return chaosPercentage < 40 ? 'CUBISM' : (chaosPercentage < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosPercentage < 40 ? 'IMPRESSIONISM' : (chaosPercentage < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
  })();

  const imgResult = await generateImageWithFallback(`Suprematist interpretation of "${finalizedTextData.title || "Revelation"}" in style of ${subStyle}. Dramatic composition.`);
  return { 
    ...finalizedTextData, 
    imageStyleLabel: subStyle.replace('_', '-'),
    base64Image: imgResult.image, 
    imageUrl: imgResult.url, 
    sources: fetchedSources.length > 0 ? fetchedSources : finalizedTextData.sources,
    language,
    isFallback: finalizedTextData.isFallback || imgResult.isFallback
  };
};

export const regenerateOracleImage = async (response: OracleResponse, artStyle: 'SUPREMATIST' | 'IMPRESSIONIST', chaosScore: number) => {
  const subStyle = (function() {
    if (artStyle === 'SUPREMATIST') return chaosScore < 40 ? 'CUBISM' : (chaosScore < 70 ? 'CONSTRUCTIVISM' : 'SUPREMATISM');
    return chaosScore < 40 ? 'IMPRESSIONISM' : (chaosScore < 70 ? 'POST_IMPRESSIONISM' : 'SYMBOLISM');
  })();
  const result = await generateImageWithFallback(`Interpretation of "${response.title}" in style of ${subStyle}.`);
  return { image: result.image, url: result.url, label: subStyle.replace('_', '-'), isFallback: result.isFallback };
};

export const translateOracleResponse = async (data: OracleResponse, targetLang: 'EN' | 'RU'): Promise<OracleResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const payload = { ...data };
  delete payload.base64Image;
  delete payload.imageUrl;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Translate this Oracle JSON to ${targetLang}. Preserve the philosophical depth and structure: ${JSON.stringify(payload)}`,
      config: { responseMimeType: "application/json", seed: 42 }
    });
    const parsed = cleanJsonResponse(response.text || "{}");
    return { ...parsed, base64Image: data.base64Image, imageUrl: data.imageUrl, language: targetLang };
  } catch (e) { return { ...data, language: targetLang }; }
};

export const speakText = async (text: string, language: 'EN' | 'RU' = 'EN') => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: language === 'RU' ? 'Puck' : 'Kore' } } }
      }
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(decode(base64Audio), context, 24000, 1);
      const source = context.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(context.destination);
      source.start();
      return { context, source };
    }
  } catch (e) { console.error("Audio generation failed:", e); }
  throw new Error("Audio generation failure.");
};
